// Per-question explanations, keyed by stable question id.
// Each entry: { de, en, src:[{label,url}] }. Shown after the answer is revealed
// (quiz with the Explain toggle on; always in browse, exam review and history review).
export const EXPLANATIONS = {
  1: {"de":"Neutralität heisst: Die Schweiz beteiligt sich nicht an Kriegen oder bewaffneten Konflikten zwischen anderen Staaten und unterstützt keine Kriegspartei militärisch. Internationale Verträge schliesst sie aber weiterhin ab.","en":"Neutrality means Switzerland does not take part in wars or armed conflicts between other states and gives no military support to any warring party. It still concludes international treaties.","src":[{"label":"Schweizerische Neutralität – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerische_Neutralit%C3%A4t"}]},
  2: {"de":"Grenzgängerinnen und Grenzgänger wohnen im Ausland (meist in einem Nachbarland) und pendeln zur Arbeit in die Schweiz.","en":"Cross-border commuters live abroad (usually in a neighbouring country) and commute to work in Switzerland.","src":[{"label":"Grenzgänger – Wikipedia","url":"https://de.wikipedia.org/wiki/Grenzg%C3%A4nger"}]},
  3: {"de":"«Confoederatio Helvetica» ist der lateinische Name der Schweizerischen Eidgenossenschaft. Daher kommen das Länderkürzel «CH» und der Währungscode «CHF».","en":"'Confoederatio Helvetica' is the Latin name of the Swiss Confederation — the source of the country code 'CH' and the currency code 'CHF'.","src":[{"label":"Confoederatio Helvetica – Wikipedia","url":"https://de.wikipedia.org/wiki/Confoederatio_Helvetica"}]},
  4: {"de":"Die Bundesverwaltung gliedert sich in sieben Departemente, je geleitet von einem Mitglied des Bundesrats — z. B. das Eidgenössische Justiz- und Polizeidepartement (EJPD). Die anderen Antworten sind keine echten Departemente.","en":"The federal administration is divided into seven departments, each led by a member of the Federal Council — e.g. the Federal Department of Justice and Police (EJPD). The other options are not real departments.","src":[{"label":"Bundesverwaltung – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesverwaltung_(Schweiz)"}]},
  5: {"de":"Nach dem Kollegialitätsprinzip vertreten alle sieben Bundesratsmitglieder die gemeinsam gefällten Entscheide nach aussen einheitlich — auch wenn einzelne persönlich anderer Meinung waren.","en":"Under the principle of collegiality, all seven Federal Council members publicly support decisions taken jointly — even if individuals personally disagreed.","src":[{"label":"Kollegialitätsprinzip – Wikipedia","url":"https://de.wikipedia.org/wiki/Kollegialit%C3%A4tsprinzip"}]},
  6: {"de":"Mit dem fakultativen Referendum kann ein bereits beschlossenes Gesetz vors Volk gebracht werden (50'000 Unterschriften in 100 Tagen). Eine Initiative dient dagegen dazu, eine neue Verfassungsänderung vorzuschlagen.","en":"An optional referendum lets voters challenge a law that has already been passed (50,000 signatures within 100 days). An initiative, by contrast, proposes a new constitutional change.","src":[{"label":"Referendum (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Referendum_(Schweiz)"}]},
  7: {"de":"Die Bundeskanzlerin oder der Bundeskanzler leitet die Bundeskanzlei und unterstützt den Bundesrat als dessen Stabsstelle (oft «achtes Regierungsmitglied» genannt) — regiert aber nicht selbst.","en":"The Federal Chancellor heads the Federal Chancellery and supports the Federal Council as its staff office (often called the 'eighth member of government') — but does not govern.","src":[{"label":"Bundeskanzler (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundeskanzler_(Schweiz)"}]},
  8: {"de":"Das «Ständemehr» ist die Mehrheit der Kantone. Verfassungsänderungen brauchen ein doppeltes Mehr: das Volksmehr (Mehrheit der Stimmen) und das Ständemehr (Mehrheit der Kantone).","en":"The 'Ständemehr' is a majority of the cantons. Constitutional amendments need a double majority: the popular majority (most votes) and the cantonal majority (most cantons).","src":[{"label":"Ständemehr – Wikipedia","url":"https://de.wikipedia.org/wiki/St%C3%A4ndemehr"}]},
  9: {"de":"Im Ausland wohnhafte Schweizerinnen und Schweizer können sich als Auslandschweizer registrieren und brieflich (teils elektronisch) an eidgenössischen Wahlen und Abstimmungen teilnehmen — ohne in die Schweiz reisen zu müssen.","en":"Swiss citizens living abroad can register as 'Swiss Abroad' and take part in federal elections and votes by post (sometimes electronically) — without travelling to Switzerland.","src":[{"label":"Auslandschweizer – Wikipedia","url":"https://de.wikipedia.org/wiki/Auslandschweizer"}]},
  10: {"de":"Das Stimm- und Wahlrecht auf Bundesebene haben Schweizer Bürgerinnen und Bürger ab 18 Jahren. Es ist also an das Schweizer Bürgerrecht gebunden.","en":"Federal voting rights belong to Swiss citizens aged 18 and over — so they are tied to Swiss citizenship.","src":[{"label":"Politische Rechte (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Rechte_(Schweiz)"}]},
  11: {"de":"Eine Partei ist ein Zusammenschluss von Menschen mit ähnlichen politischen Zielen und Wertvorstellungen, die diese gemeinsam in der Politik durchsetzen wollen.","en":"A political party is an association of people with similar political goals and values who want to advance them together in politics.","src":[{"label":"Politische Partei – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Partei"}]},
  12: {"de":"Die Geldpolitik ist Bundessache und Aufgabe der Schweizerischen Nationalbank (SNB). Wasserversorgung, Polizei und Volksschule sind dagegen Sache der Kantone und Gemeinden.","en":"Monetary policy is a federal matter, handled by the Swiss National Bank (SNB). Water supply, police and public schools, by contrast, are the responsibility of cantons and municipalities.","src":[{"label":"Schweizerische Nationalbank – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerische_Nationalbank"}]},
  13: {"de":"Der Zoll (Grenzschutz, Ein- und Ausfuhrabgaben) ist Aufgabe des Bundes, ausgeübt durch das Bundesamt für Zoll und Grenzsicherheit (BAZG). Feuerwehr, Parks und Spitäler sind kantonal oder kommunal.","en":"Customs (border control, import/export duties) is a federal task, run by the Federal Office for Customs and Border Security (FOCBS). Fire brigades, parks and hospitals are cantonal or municipal.","src":[{"label":"BAZG – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesamt_f%C3%BCr_Zoll_und_Grenzsicherheit"}]},
  14: {"de":"Die Meinungs- und Informationsfreiheit ist ein Grundrecht der Bundesverfassung (Art. 16): jede Person darf ihre Meinung frei bilden, äussern und sich informieren.","en":"Freedom of opinion and information is a fundamental right in the Federal Constitution (Art. 16): everyone may freely form and express opinions and gather information.","src":[{"label":"Bundesverfassung Art. 16 – fedlex.admin.ch","url":"https://www.fedlex.admin.ch/eli/cc/1999/404/de"}]},
  15: {"de":"Die Glaubens- und Gewissensfreiheit ist ein Grundrecht (Art. 15 BV). Ein einklagbares «Recht auf Arbeit» oder «Recht auf eine Wohnung» garantiert die Verfassung dagegen nicht.","en":"Freedom of religion and conscience is a fundamental right (Art. 15 of the Constitution). By contrast, the constitution does not guarantee an enforceable 'right to work' or 'right to housing'.","src":[{"label":"Bundesverfassung Art. 15 – fedlex.admin.ch","url":"https://www.fedlex.admin.ch/eli/cc/1999/404/de"}]},
  16: {"de":"Alle Einwohnerinnen und Einwohner der Schweiz sind verpflichtet, Steuern zu bezahlen; mit diesen Abgaben werden öffentliche Aufgaben wie Schulen, Strassen und Sicherheit finanziert. Eine Lehre, ein Bankkonto oder ein Führerausweis sind hingegen freiwillig.","en":"Everyone living in Switzerland is obliged to pay taxes, which fund public tasks such as schools, roads and security. An apprenticeship, a bank account or a driving licence, by contrast, are voluntary.","src":[{"label":"Direkte und indirekte Steuer – Wikipedia","url":"https://de.wikipedia.org/wiki/Direkte_und_indirekte_Steuer"}]},
  17: {"de":"Wer in der Schweiz wohnt, muss sich bei Zuzug innert weniger Tage bei der Wohngemeinde (Einwohnerkontrolle) anmelden. Kirchenmitgliedschaft, Weiterbildung oder ein Telefon sind keine gesetzlichen Pflichten.","en":"Anyone living in Switzerland must register with their municipality of residence (residents' registration office) shortly after moving in. Church membership, further education or owning a phone are not legal obligations.","src":[{"label":"Einwohnerkontrolle – Wikipedia","url":"https://de.wikipedia.org/wiki/Einwohnerkontrolle"}]},
  18: {"de":"In der Schweiz besteht eine obligatorische Krankenversicherung: Jede in der Schweiz wohnhafte Person muss sich bei einer Krankenkasse versichern. Eine Diebstahlversicherung, ein Halbtax oder Hauseigentum sind freiwillig.","en":"Switzerland has compulsory health insurance: every person resident in Switzerland must take out cover with a health insurer. Theft insurance, a half-fare travel card or owning a house are voluntary.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  19: {"de":"Rechtsgleichheit bedeutet, dass alle Menschen vor dem Gesetz gleich behandelt werden; sie ist in Artikel 8 der Bundesverfassung verankert. Sie garantiert keine gleichen Löhne, gleichen Ferien oder identische Gesetze in allen Kantonen.","en":"Equality before the law means that all people are treated equally by the law; it is enshrined in Article 8 of the Federal Constitution. It does not guarantee equal salaries, equal holidays or identical laws in every canton.","src":[{"label":"Rechtsgleichheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Rechtsgleichheit"}]},
  20: {"de":"Das Schweizer Parlament (Bundesversammlung) besteht aus zwei gleichberechtigten Kammern: dem Nationalrat (Volksvertretung) und dem Ständerat (Kantonsvertretung). 'Ober-/Unterhaus' oder 'Senat/Kongress' sind Bezeichnungen anderer Staaten.","en":"The Swiss parliament (Federal Assembly) consists of two equal chambers: the National Council (representing the people) and the Council of States (representing the cantons). Terms like 'Upper/Lower House' or 'Senate/Congress' belong to other countries.","src":[{"label":"Bundesversammlung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesversammlung_(Schweiz)"}]},
  21: {"de":"Die Schweiz ist eine Demokratie, in der das Volk über Wahlen und Abstimmungen mitbestimmt; sie ist insbesondere für ihre direkte Demokratie bekannt. Sie ist weder Diktatur, absolutistischer Staat noch Fürstentum.","en":"Switzerland is a democracy in which the people have a say through elections and referendums; it is especially known for its direct democracy. It is neither a dictatorship, an absolutist state nor a principality.","src":[{"label":"Politisches System der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Politisches_System_der_Schweiz"}]},
  22: {"de":"Ein zentrales Merkmal der Demokratie ist, dass das Volk seine Vertretung – das Parlament – wählt und so die Macht vom Volk ausgeht. Reisefreiheit oder ein Grundeinkommen sind keine Definitionsmerkmale der Demokratie, und ein König widerspricht ihr.","en":"A key feature of democracy is that the people elect their representatives – the parliament – so that power derives from the people. Freedom to travel or a basic income are not defining features of democracy, and rule by a king contradicts it.","src":[{"label":"Demokratie – Wikipedia","url":"https://de.wikipedia.org/wiki/Demokratie"}]},
  23: {"de":"Regelmässige Wahlen sorgen dafür, dass das Volk seine Volksvertretung selbst bestimmen und periodisch erneuern oder abwählen kann; so bleibt die Macht beim Volk und die Gewählten bleiben rechenschaftspflichtig.","en":"Regular elections ensure that the people themselves choose their representatives and can periodically renew or vote them out, keeping power with the people and holding the elected accountable.","src":[{"label":"Wahl – Wikipedia","url":"https://de.wikipedia.org/wiki/Wahl"}]},
  24: {"de":"Die Verfassung der Schweiz heisst Bundesverfassung der Schweizerischen Eidgenossenschaft (in Kraft seit 1. Januar 2000). 'Grundgesetz' ist die deutsche, der 'Bundesbrief' ein historisches Bündnisdokument von 1291.","en":"Switzerland's constitution is called the Federal Constitution of the Swiss Confederation (in force since 1 January 2000). 'Grundgesetz' is Germany's term, while the 'Bundesbrief' is a historical alliance charter from 1291.","src":[{"label":"Bundesverfassung – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesverfassung_der_Schweizerischen_Eidgenossenschaft"}]},
  25: {"de":"Der Bundesrat ist die Landesregierung und führt die Regierungsgeschäfte der Schweiz; er besteht aus sieben gleichberechtigten Mitgliedern. Die Bundesversammlung ist das Parlament, nicht die Regierung.","en":"The Federal Council is the national government and runs the executive affairs of Switzerland; it consists of seven equal members. The Federal Assembly is the parliament, not the government.","src":[{"label":"Schweizerischer Bundesrat – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerischer_Bundesrat"}]},
  26: {"de":"Bundesgesetze werden von beiden Parlamentskammern – Nationalrat und Ständerat – beschlossen; zusätzlich kann das Volk über das fakultative Referendum mitentscheiden. Das Bundesgericht spricht Recht, erlässt aber keine Gesetze.","en":"Federal laws are passed by both chambers of parliament – the National Council and the Council of States – and the people can also have a say through the optional referendum. The Federal Supreme Court applies the law but does not enact it.","src":[{"label":"Bundesversammlung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesversammlung_(Schweiz)"}]},
  27: {"de":"Auf Bundesebene stimm- und wahlberechtigt sind alle Schweizerinnen und Schweizer ab dem vollendeten 18. Lebensjahr (sofern nicht wegen Urteilsunfähigkeit entmündigt). Wohnsitz, Steuerzahlung oder ein leeres Strafregister sind keine Voraussetzungen.","en":"At federal level, all Swiss citizens aged 18 and over are entitled to vote and elect (unless placed under guardianship for incapacity). Residence, paying taxes or a clean criminal record are not requirements.","src":[{"label":"Politische Rechte (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Rechte_(Schweiz)"}]},
  28: {"de":"Auf Bundesebene sind alle Schweizerinnen und Schweizer ab dem vollendeten 18. Altersjahr stimm- und wahlberechtigt; dies entspricht dem Erreichen der Volljährigkeit. Die anderen Altersangaben (21, 25 oder 16 Jahre) gelten nicht.","en":"At federal level, all Swiss citizens are entitled to vote and stand for election from the age of 18, which coincides with reaching the age of majority. The other ages (21, 25 or 16) do not apply.","src":[{"label":"Politische Rechte (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Rechte_(Schweiz)"}]},
  29: {"de":"Das aktive Wahlrecht ist das Recht, selbst zu wählen und abzustimmen. Davon zu unterscheiden ist das passive Wahlrecht, also die Möglichkeit, selbst in ein Amt gewählt zu werden; eine Parteimitgliedschaft oder Mithilfe beim Auszählen ist nicht erforderlich.","en":"Active suffrage is the right to vote and take part in ballots oneself. This is distinct from passive suffrage, the right to be elected to office; party membership or helping count votes is not required.","src":[{"label":"Wahlrecht – Wikipedia","url":"https://de.wikipedia.org/wiki/Wahlrecht"}]},
  30: {"de":"In ein politisches Amt auf Bundesebene kann gewählt werden, wer das Schweizer Bürgerrecht besitzt und volljährig (18 Jahre) ist – das ist das passive Wahlrecht. Eine Arbeitsstelle, blosser Wohnsitz oder Sprachkenntnisse sind keine Voraussetzung.","en":"You can be elected to political office at federal level if you hold Swiss citizenship and are of age (18) – this is passive suffrage. Having a job, merely residing in Switzerland, or speaking several languages is not required.","src":[{"label":"Politische Rechte (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Rechte_(Schweiz)"}]},
  31: {"de":"Dank der direkten Demokratie können Schweizer Stimmbürgerinnen und Stimmbürger über Volksinitiativen und Referenden direkt auf die Gesetzgebung einwirken. Damit haben sie sehr wohl eine direkte Einflussmöglichkeit, die über das blosse Wählen oder einen Parteibeitritt hinausgeht.","en":"Thanks to direct democracy, Swiss voters can influence legislation directly through popular initiatives and referendums. They therefore do have a direct say that goes beyond merely voting or joining a party.","src":[{"label":"Direkte Demokratie – Wikipedia","url":"https://de.wikipedia.org/wiki/Direkte_Demokratie"}]},
  32: {"de":"Das (fakultative) Referendum richtet sich gegen Gesetzesvorlagen, die von National- und Ständerat beschlossen wurden; kommen genügend Unterschriften zusammen, entscheidet das Volk. Gegen Beschlüsse des Bundesrats, Urteile des Bundesgerichts oder Verwaltungsmassnahmen gibt es kein Referendum.","en":"The (optional) referendum is directed against legislative acts passed by the National Council and Council of States; if enough signatures are gathered, the people decide. There is no referendum against decisions of the Federal Council, rulings of the Federal Supreme Court, or administrative measures.","src":[{"label":"Referendum (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Referendum_(Schweiz)"}]},
  33: {"de":"Mit einer Volksinitiative kann die Bevölkerung eine Änderung der Bundesverfassung verlangen und so eigene Anliegen auf die politische Agenda bringen und durchsetzen. Sie schaltet weder das Parlament aus noch wählt sie die Regierung ab oder macht automatisch Entscheide rückgängig.","en":"A popular initiative lets the public demand a change to the Federal Constitution, putting their own concerns on the political agenda and pushing them through. It neither sidelines parliament nor dismisses the government, and it does not automatically reverse decisions.","src":[{"label":"Eidgenössische Volksinitiative – Wikipedia","url":"https://de.wikipedia.org/wiki/Eidgen%C3%B6ssische_Volksinitiative"}]},
  34: {"de":"Der Nationalrat wird alle vier Jahre neu gewählt; in der Regel werden zugleich auch die Ständerätinnen und Ständeräte gewählt. Die Legislaturperiode des Bundesparlaments beträgt somit vier Jahre.","en":"The National Council is re-elected every four years, and the members of the Council of States are usually elected at the same time. The term of the federal parliament is therefore four years.","src":[{"label":"Nationalrat (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Nationalrat_(Schweiz)"}]},
  35: {"de":"Die 246 Mitglieder der Bundesversammlung – 200 im Nationalrat und 46 im Ständerat – werden von den wahlberechtigten Bürgerinnen und Bürgern direkt gewählt. Nicht alle Einwohnerinnen und Einwohner sind wahlberechtigt, und weder die Parteien noch eine Wahlkommission bestimmen die Mitglieder.","en":"The 246 members of the Federal Assembly – 200 in the National Council and 46 in the Council of States – are elected directly by the citizens entitled to vote. Not all residents may vote, and neither the parties nor any electoral commission appoint the members.","src":[{"label":"Bundesversammlung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesversammlung_(Schweiz)"}]},
  36: {"de":"Auf Bundesebene stimmt das Volk über Volksinitiativen und Referenden ab; das ist der Kern der direkten Demokratie. Über Parteiprogramme, das Radio- und Fernsehprogramm oder die Besetzung von Verwaltungsstellen wird nicht abgestimmt.","en":"At federal level the people vote on popular initiatives and referendums – the core of direct democracy. Party programmes, radio and TV schedules, or the filling of administrative posts are not put to a vote.","src":[{"label":"Direkte Demokratie – Wikipedia","url":"https://de.wikipedia.org/wiki/Direkte_Demokratie"}]},
  37: {"de":"Die zentrale Aufgabe der Bundesversammlung als Legislative ist es, Gesetze zu beraten und zu beschliessen. Das Regieren obliegt dem Bundesrat, die Rechtsprechung den Gerichten; Wahlen und Abstimmungen werden von den Behörden organisiert.","en":"The central task of the Federal Assembly as the legislative branch is to debate and pass laws. Governing is the job of the Federal Council and adjudication that of the courts; elections and ballots are organised by the authorities.","src":[{"label":"Bundesversammlung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesversammlung_(Schweiz)"}]},
  38: {"de":"Die Vereinigte Bundesversammlung besteht aus den Mitgliedern von Nationalrat und Ständerat, die gemeinsam tagen – etwa um den Bundesrat, das Bundesgericht oder den Bundeskanzler zu wählen. Bundesrichter, Kantonsregierungen oder Parteipräsidien gehören ihr nicht an.","en":"The United Federal Assembly consists of the members of the National Council and the Council of States meeting jointly – for example to elect the Federal Council, the Federal Supreme Court, or the Federal Chancellor. Federal judges, cantonal governments, and party presidents are not part of it.","src":[{"label":"Vereinigte Bundesversammlung – Wikipedia","url":"https://de.wikipedia.org/wiki/Vereinigte_Bundesversammlung"}]},
  39: {"de":"Das Bundeshaus in Bern ist der Sitz der Bundesversammlung (des Schweizer Parlaments) sowie des Bundesrats. Nationalmuseum, Universität oder das Schweizer Fernsehen sind dort nicht untergebracht.","en":"The Federal Palace (Bundeshaus) in Bern is the seat of the Federal Assembly (the Swiss parliament) as well as the Federal Council. The national museum, the university, and Swiss television are not housed there.","src":[{"label":"Bundeshaus (Bern) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundeshaus_(Bern)"}]},
  40: {"de":"Der Bundesrat ist die Exekutive (Regierung) der Schweiz auf Bundesebene und besteht aus sieben gleichberechtigten Mitgliedern. Grosser Rat und Landrat sind kantonale Parlamente, der Generalrat ist kein Schweizer Bundesorgan.","en":"The Bundesrat (Federal Council) is Switzerland's executive (government) at federal level and consists of seven members with equal rights. The Grosser Rat and Landrat are cantonal parliaments, and the Generalrat is not a Swiss federal body.","src":[{"label":"Schweizerischer Bundesrat – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerischer_Bundesrat"}]},
  41: {"de":"Die sieben Bundesräte werden von der Vereinigten Bundesversammlung gewählt, also von National- und Ständerat gemeinsam. Sie werden nicht direkt vom Volk gewählt.","en":"The seven Federal Councillors are elected by the United Federal Assembly, that is, by the National Council and the Council of States together. They are not elected directly by the people.","src":[{"label":"Schweizerischer Bundesrat – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerischer_Bundesrat"}]},
  42: {"de":"Parteien bündeln und vertreten die unterschiedlichen Interessen und Anliegen der Bevölkerung im politischen Prozess. Die Regierung wird vom Parlament (nicht von den Parteien selbst) gewählt, und Medienkontrolle ist keine Parteiaufgabe.","en":"Parties pool and represent the various interests and concerns of the population in the political process. The government is elected by parliament (not by the parties themselves), and controlling the media is not a party function.","src":[{"label":"Politische Partei – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Partei"}]},
  43: {"de":"Für eine eidgenössische Volksinitiative müssen innerhalb von 18 Monaten 100'000 gültige Unterschriften gesammelt werden. Damit kann eine Änderung der Bundesverfassung verlangt werden.","en":"A federal popular initiative requires 100,000 valid signatures collected within 18 months. With it, a change to the Federal Constitution can be demanded.","src":[{"label":"Volksinitiative (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksinitiative_(Schweiz)"}]},
  44: {"de":"Der Ständerat ist die Kammer, die vor allem die Interessen der Kantone vertritt; jeder Kanton stellt zwei Mitglieder, die ehemaligen Halbkantone je eines. Zusammen mit dem Nationalrat bildet er die Bundesversammlung.","en":"The Council of States is the chamber that mainly represents the interests of the cantons; each canton provides two members, the former half-cantons one each. Together with the National Council it forms the Federal Assembly.","src":[{"label":"Ständerat – Wikipedia","url":"https://de.wikipedia.org/wiki/St%C3%A4nderat"}]},
  45: {"de":"Als Vereinigte Bundesversammlung wählen National- und Ständerat gemeinsam unter anderem die Mitglieder des Bundesrats und des Bundesgerichts. Das Bundesgericht selbst fällt die Urteile, nicht das Parlament.","en":"Sitting jointly as the United Federal Assembly, the National Council and the Council of States together elect, among others, the members of the Federal Council and the Federal Supreme Court. The Federal Supreme Court itself renders judgments, not parliament.","src":[{"label":"Vereinigte Bundesversammlung – Wikipedia","url":"https://de.wikipedia.org/wiki/Vereinigte_Bundesversammlung"}]},
  46: {"de":"In der Regel finden pro Jahr vier eidgenössische Abstimmungstermine statt, an denen das Stimmvolk über Vorlagen entscheidet. Die Termine werden vom Bundesrat im Voraus festgelegt.","en":"As a rule there are four federal voting dates per year on which the electorate decides on proposals. The dates are set in advance by the Federal Council.","src":[{"label":"Volksabstimmung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksabstimmung_(Schweiz)"}]},
  47: {"de":"Der grösste Teil der neuen Bundesgesetze wird vom Parlament beschlossen, also von National- und Ständerat gemeinsam. Der Bundesrat bereitet Vorlagen vor, das Bundesgericht spricht Recht und beschliesst keine Gesetze.","en":"Most new federal laws are passed by parliament, that is, by the National Council and the Council of States together. The Federal Council prepares the bills, while the Federal Supreme Court administers justice and does not pass laws.","src":[{"label":"Bundesversammlung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesversammlung_(Schweiz)"}]},
  48: {"de":"Eine eidgenössische Volksinitiative ist nur angenommen, wenn sie das doppelte Mehr erreicht: Volksmehr (Mehrheit der gültigen Stimmen) und Ständemehr (Mehrheit der Kantone). Beides muss gleichzeitig erfüllt sein.","en":"A federal popular initiative is only accepted if it achieves the double majority: a majority of the people (of valid votes) and a majority of the cantons. Both must be met at the same time.","src":[{"label":"Volksinitiative (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksinitiative_(Schweiz)"}]},
  49: {"de":"Mit einer Volksinitiative kann eine Teil- oder Totalrevision der Bundesverfassung verlangt werden. Sie kann weder Gesetze des Völkerrechts ändern noch Parlament oder Bundesrat absetzen.","en":"A popular initiative can demand a partial or total revision of the Federal Constitution. It cannot change international law, nor remove parliament or the Federal Council from office.","src":[{"label":"Volksinitiative (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksinitiative_(Schweiz)"}]},
  50: {"de":"Die grosse Mehrheit der Stimmberechtigten stimmt heute brieflich ab; die briefliche Stimmabgabe ist in der ganzen Schweiz möglich und weit verbreiteter als der Gang an die Urne. E-Voting ist nur eingeschränkt verfügbar.","en":"Today the large majority of voters vote by post; postal voting is available throughout Switzerland and far more common than going to the ballot box in person. E-voting is only available to a limited extent.","src":[{"label":"Briefwahl – Wikipedia","url":"https://de.wikipedia.org/wiki/Briefwahl"}]},
  51: {"de":"Eidgenössische Wahlen und Abstimmungen finden in der Schweiz traditionell am Sonntag statt; die brieflich abgegebenen Stimmen müssen bis dahin eingetroffen sein. Der Sonntag ist der offizielle Abstimmungstag.","en":"Federal elections and popular votes in Switzerland traditionally take place on a Sunday; postal votes must have arrived by then. Sunday is the official voting day.","src":[{"label":"Volksabstimmung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksabstimmung_(Schweiz)"}]},
  52: {"de":"Soziale Sicherheit (z. B. AHV/IV, Krankenversicherung, Arbeitslosenversicherung) ist eine zentrale Aufgabe des Bundesstaats. Die Organisation der Fabrikarbeit liegt bei den Unternehmen, und für Wohnraum oder die Herausgabe von Zeitungen ist der Staat nicht zuständig.","en":"Providing social security (e.g. old-age and disability insurance, health and unemployment insurance) is a core task of the federal state. Organising factory work is up to companies, and the state is not responsible for housing or publishing newspapers.","src":[{"label":"Soziale Sicherheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Soziale_Sicherheit"}]},
  53: {"de":"Der Bund sorgt für die innere und äussere Sicherheit, etwa durch die Armee, den Grenzschutz und die Koordination der Polizei. Vereins- und Firmengründungen sind privat organisiert, und eigene Spitäler betreibt vor allem der Kanton, nicht der Bund.","en":"The Confederation is responsible for internal and external security, for example through the army, border protection and police coordination. Founding clubs or companies is a private matter, and hospitals are mainly run by the cantons, not the federal level.","src":[{"label":"Politisches System der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Politisches_System_der_Schweiz"}]},
  54: {"de":"Der Umweltschutz ist eine wichtige Bundesaufgabe und in der Bundesverfassung verankert (z. B. Gewässer-, Natur- und Klimaschutz). Die Leitzinsen setzt die unabhängige Nationalbank fest, und Autoproduktion oder Elektrizitätswerke betreibt der Bund nicht.","en":"Environmental protection is an important federal task anchored in the Federal Constitution (e.g. protection of water, nature and climate). Interest rates are set by the independent National Bank, and the Confederation does not build cars or run power plants.","src":[{"label":"Umweltschutz – Wikipedia","url":"https://de.wikipedia.org/wiki/Umweltschutz"}]},
  55: {"de":"Die Schweizer Nationalfahne ist eine quadratische rote Flagge mit einem weissen, gleicharmigen Kreuz in der Mitte. Die anderen Beschreibungen (versetztes Kreuz, vertauschte Farben oder Kreuz in der Ecke) treffen nicht zu.","en":"The Swiss national flag is a square red flag with a white, equal-armed cross in the centre. The other descriptions (off-centre cross, reversed colours or a corner cross) are incorrect.","src":[{"label":"Flagge der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Flagge_der_Schweiz"}]},
  56: {"de":"Der Schweizer Bundesstaat setzt sich aus Kantonen zusammen, den Gliedstaaten mit eigener Verfassung und weitgehender Autonomie. Begriffe wie Bundesländer, Distrikte oder Provinzen werden in anderen Staaten verwendet, nicht in der Schweiz.","en":"The Swiss federal state is made up of cantons, the constituent states with their own constitutions and broad autonomy. Terms like federal states (Bundesländer), districts or provinces are used in other countries, not in Switzerland.","src":[{"label":"Kanton (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_(Schweiz)"}]},
  57: {"de":"Die Schweiz besteht aus 26 Kantonen; sechs davon werden historisch als Halbkantone bezeichnet, weshalb auch von 20 Kantonen und 6 Halbkantonen gesprochen wird. Staatsrechtlich zählen heute alle als gleichwertige Kantone, doch die sechs verfügen je über nur eine Standesstimme und einen Ständeratssitz.","en":"Switzerland consists of 26 cantons; six are historically called half-cantons, hence the phrasing of 20 cantons and 6 half-cantons. Legally all count as equal cantons today, but the six each hold only one half cantonal vote and one seat in the Council of States.","src":[{"label":"Kanton (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_(Schweiz)"}]},
  58: {"de":"In der Schweiz gibt es rund 2200 politische Gemeinden (Stand 2021); durch laufende Gemeindefusionen nimmt die Zahl stetig ab. Sie bilden die unterste der drei Staatsebenen.","en":"Switzerland has roughly 2,200 political municipalities (as of 2021); the number keeps falling due to ongoing municipal mergers. They form the lowest of the three state levels.","src":[{"label":"Politische Gemeinde – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Gemeinde"}]},
  59: {"de":"Die unterste der drei Staatsebenen ist die Gemeinde, gefolgt vom Kanton und zuoberst dem Bund. Der Bezirk ist keine eigene Staatsebene, sondern eine Verwaltungseinheit innerhalb mancher Kantone.","en":"The lowest of the three state levels is the municipality, followed by the canton and, at the top, the Confederation. The district is not a separate state level but an administrative unit within some cantons.","src":[{"label":"Föderalismus in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/F%C3%B6deralismus_in_der_Schweiz"}]},
  60: {"de":"Die oberste der drei Staatsebenen ist der Bund (die Eidgenossenschaft), darunter folgen die Kantone und zuunterst die Gemeinden. Der Bund regelt gesamtschweizerische Aufgaben wie Aussenpolitik und Landesverteidigung.","en":"The highest of the three state levels is the Confederation (the federal state), below it the cantons and at the bottom the municipalities. The Confederation handles nationwide matters such as foreign policy and national defence.","src":[{"label":"Föderalismus in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/F%C3%B6deralismus_in_der_Schweiz"}]},
  61: {"de":"Die Aussenpolitik ist Sache des Bundes, der die Schweiz gegenüber dem Ausland vertritt und Staatsverträge abschliesst. Volksschule, Bauordnungen und die Wahl der Kantonsrichter fallen dagegen in die Zuständigkeit der Kantone oder Gemeinden.","en":"Foreign policy is a matter for the Confederation, which represents Switzerland abroad and concludes treaties. Primary schooling, building regulations and the election of cantonal judges, by contrast, fall under the cantons or municipalities.","src":[{"label":"Aussenpolitik der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Aussenpolitik_der_Schweiz"}]},
  62: {"de":"Für das Militär ist der Bund zuständig; die Schweizer Armee ist eine nationale Aufgabe, auch wenn die Kantone bei der Aushebung mitwirken. Kanton, Bezirk und Gemeinde haben keine eigenen Streitkräfte.","en":"The military is the responsibility of the Confederation; the Swiss Armed Forces are a national matter, even though the cantons assist with recruitment. Cantons, districts and municipalities have no armed forces of their own.","src":[{"label":"Schweizer Armee – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_Armee"}]},
  63: {"de":"Die vier Landessprachen der Schweiz sind Deutsch, Französisch, Italienisch und Rätoromanisch. Englisch ist keine Landessprache, und Dialekte gelten nicht als eigenständige Landessprachen.","en":"Switzerland's four national languages are German, French, Italian and Romansh. English is not a national language, and dialects do not count as separate national languages.","src":[{"label":"Sprachen in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Sprachen_in_der_Schweiz"}]},
  64: {"de":"Französisch ist neben Deutsch, Italienisch und Rätoromanisch eine der vier offiziellen Landessprachen der Schweiz. Englisch, Portugiesisch und Spanisch werden zwar gesprochen, haben aber keinen offiziellen Status.","en":"Alongside German, Italian and Romansh, French is one of Switzerland's four official national languages. English, Portuguese and Spanish are spoken but have no official status.","src":[{"label":"Sprachen in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Sprachen_in_der_Schweiz"}]},
  65: {"de":"Die Schweiz hat vier offizielle Landessprachen: Deutsch, Französisch, Italienisch und Rätoromanisch. Dies ist in der Bundesverfassung verankert.","en":"Switzerland has four official national languages: German, French, Italian and Romansh. This is enshrined in the Federal Constitution.","src":[{"label":"Sprachen in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Sprachen_in_der_Schweiz"}]},
  66: {"de":"Die vierte Landessprache der Schweiz ist Rätoromanisch, das vor allem im Kanton Graubünden gesprochen wird. Elsässisch und Englisch sind keine Landessprachen.","en":"Switzerland's fourth national language is Romansh, spoken mainly in the canton of Graubünden. Alsatian and English are not national languages.","src":[{"label":"Bündnerromanisch – Wikipedia","url":"https://de.wikipedia.org/wiki/B%C3%BCndnerromanisch"}]},
  67: {"de":"In der Schweiz hat allein der Staat das Gewaltmonopol: Nur staatliche Organe wie Polizei und Militär dürfen rechtmässig physische Gewalt ausüben. Bürgerinnen und Bürger, Parteien oder Medien dürfen sich nicht selbst Recht verschaffen.","en":"In Switzerland only the state holds the monopoly on the use of force: solely state organs such as the police and the military may lawfully exercise physical force. Citizens, parties or the media may not take the law into their own hands.","src":[{"label":"Gewaltmonopol des Staates – Wikipedia","url":"https://de.wikipedia.org/wiki/Gewaltmonopol_des_Staates"}]},
  68: {"de":"Die richterliche Gewalt (Judikative) auf Bundesebene liegt beim Bundesgericht, dem obersten Gericht der Schweiz. Parlament, Regierung und Militär gehören anderen Gewalten an.","en":"At the federal level the judicial power (judiciary) lies with the Federal Supreme Court, Switzerland's highest court. Parliament, government and the military belong to other branches.","src":[{"label":"Bundesgericht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesgericht_(Schweiz)"}]},
  69: {"de":"Die gesetzgebende Gewalt (Legislative) liegt beim Bundesparlament, der Bundesversammlung, die aus Nationalrat und Ständerat besteht. Der Bundesrat (Exekutive) und das Bundesgericht (Judikative) erfüllen andere Funktionen.","en":"Legislative power lies with the federal parliament, the Federal Assembly, made up of the National Council and the Council of States. The Federal Council (executive) and the Federal Supreme Court (judiciary) perform other functions.","src":[{"label":"Bundesversammlung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesversammlung_(Schweiz)"}]},
  70: {"de":"Die ausführende Gewalt (Exekutive) auf Bundesebene hat der Bundesrat, die siebenköpfige Landesregierung der Schweiz. Das Parlament gehört zur Legislative, die Gerichte zur Judikative.","en":"At the federal level the executive power lies with the Federal Council, Switzerland's seven-member national government. Parliament belongs to the legislature and the courts to the judiciary.","src":[{"label":"Schweizerischer Bundesrat – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerischer_Bundesrat"}]},
  71: {"de":"Als vierte Gewalt im Staat bezeichnet man häufig die Medien (Zeitungen, Radio, Fernsehen), weil sie durch Berichterstattung Politik und Verwaltung kontrollieren und die öffentliche Meinung bilden. Sie sind aber keine formelle Staatsgewalt.","en":"The media (newspapers, radio, television) are often called the fourth power in the state because their reporting scrutinises politics and administration and shapes public opinion. They are, however, not a formal branch of government.","src":[{"label":"Vierte Gewalt – Wikipedia","url":"https://de.wikipedia.org/wiki/Vierte_Gewalt"}]},
  72: {"de":"Richterinnen und Richter sind Teil der Judikative; ihre Aufgabe ist es, Recht zu sprechen und Gerichtsurteile zu fällen. Die Verteidigung der Angeklagten übernehmen Anwälte, und Gesetze macht das Parlament.","en":"Judges are part of the judiciary; their task is to administer justice and hand down court rulings. Defending the accused is the role of lawyers, and laws are made by parliament.","src":[{"label":"Richter – Wikipedia","url":"https://de.wikipedia.org/wiki/Richter"}]},
  73: {"de":"Eine zentrale Aufgabe der Polizei ist es, Rechtsverletzungen zu verfolgen und für Sicherheit und Ordnung zu sorgen. Gesetze erlassen das Parlament und Urteile fällen die Gerichte.","en":"A core task of the police is to pursue violations of the law and to maintain safety and order. Laws are enacted by parliament and verdicts are handed down by the courts.","src":[{"label":"Polizei – Wikipedia","url":"https://de.wikipedia.org/wiki/Polizei"}]},
  74: {"de":"Das Verhaften von Kriminellen ist Aufgabe der Polizei als Trägerin des staatlichen Gewaltmonopols. Privatpersonen, Zeugen oder eine \"Bürgerwehr\" dürfen dies nicht; der Gemeinderat hat keine polizeilichen Befugnisse.","en":"Arresting criminals is the task of the police, which holds the state's monopoly on the use of force. Private individuals, witnesses or a \"vigilante group\" may not do so, and the municipal council has no police powers.","src":[{"label":"Polizei – Wikipedia","url":"https://de.wikipedia.org/wiki/Polizei"}]},
  75: {"de":"Gewaltenteilung bedeutet die Verteilung der Staatsgewalt auf verschiedene, voneinander unabhängige Organe – Legislative (Parlament), Exekutive (Regierung) und Judikative (Gerichte). So wird Machtkonzentration und Missbrauch vorgebeugt.","en":"Separation of powers means dividing state authority among separate, mutually independent organs: the legislature (parliament), the executive (government) and the judiciary (courts). This prevents the concentration and abuse of power.","src":[{"label":"Gewaltenteilung – Wikipedia","url":"https://de.wikipedia.org/wiki/Gewaltenteilung"}]},
  76: {"de":"In einem Rechtsstaat ist alle staatliche Tätigkeit an Recht und Gesetz gebunden – auch Behörden, Regierung und Verwaltung dürfen nur handeln, was das Gesetz erlaubt. Die anderen Antworten sind falsch, weil Gesetze für alle Menschen im Land gelten, unabhängig von Zustimmung, Nationalität oder politischem Amt.","en":"In a state governed by the rule of law, all state action is bound by the law – authorities, the government and the administration may only act within what the law permits. The other answers are wrong because laws apply to everyone in the country, regardless of consent, nationality or political office.","src":[{"label":"Rechtsstaat – Wikipedia","url":"https://de.wikipedia.org/wiki/Rechtsstaat"}]},
  77: {"de":"Die Glaubens- und Gewissensfreiheit ist als Grundrecht in der Bundesverfassung (Art. 15) verankert. Waffenbesitz, ein eigenes Haus oder persönliche Rache sind dagegen keine in der Verfassung garantierten Grundrechte.","en":"Freedom of belief and conscience is a fundamental right anchored in the Federal Constitution (Art. 15). Gun ownership, owning a house or personal revenge are not constitutionally guaranteed fundamental rights.","src":[{"label":"Religionsfreiheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Religionsfreiheit"}]},
  78: {"de":"Die Meinungsfreiheit ist ein klassisches Grundrecht und in der Bundesverfassung (Art. 16) garantiert. Ein Recht auf WLAN, kostenlose Weiterbildung oder das Halten von Haustieren ist hingegen nicht in der Verfassung verankert.","en":"Freedom of opinion is a classic fundamental right guaranteed by the Federal Constitution (Art. 16). A right to Wi-Fi, free further education or keeping pets is not anchored in the constitution.","src":[{"label":"Meinungsfreiheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Meinungsfreiheit"}]},
  79: {"de":"Die Glaubens- und Gewissensfreiheit garantiert vor allem die Religionsfreiheit, also das Recht, seine Religion frei zu wählen, auszuüben oder auch keiner Religion anzugehören. Freie Schulwahl, Freizeit oder Versammlungsfreiheit gehören nicht zu diesem Grundrecht.","en":"Freedom of belief and conscience guarantees above all religious freedom – the right to freely choose and practise one's religion, or to belong to no religion at all. Free choice of school, leisure time or freedom of assembly are not part of this right.","src":[{"label":"Religionsfreiheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Religionsfreiheit"}]},
  80: {"de":"Die rechtliche Gleichstellung bedeutet, dass Frauen und Männer grundsätzlich die gleichen Rechte und Pflichten haben (Art. 8 BV). Sie schreibt aber keine festen Geschlechterquoten in Gremien vor und teilt Aufgaben wie Kochen oder Kindererziehung keinem Geschlecht zu.","en":"Legal equality means that women and men fundamentally have the same rights and duties (Art. 8 of the Constitution). It does not prescribe fixed gender quotas in bodies, nor does it assign tasks like cooking or raising children to a particular sex.","src":[{"label":"Gleichberechtigung – Wikipedia","url":"https://de.wikipedia.org/wiki/Gleichberechtigung"}]},
  81: {"de":"Das öffentliche Verbreiten falscher Tatsachenbehauptungen über eine Person verletzt deren Ehre und ist als üble Nachrede bzw. Verleumdung strafbar. Regierungskritik, die Scheidung einer Ehe und die Teilnahme an Demonstrationen sind dagegen erlaubt und durch Grundrechte geschützt.","en":"Publicly spreading false factual claims about a person harms their honour and is punishable as defamation or slander. Criticising the government, dissolving a marriage and taking part in demonstrations, by contrast, are permitted and protected by fundamental rights.","src":[{"label":"Üble Nachrede – Wikipedia","url":"https://de.wikipedia.org/wiki/%C3%9Cble_Nachrede"}]},
  82: {"de":"Wird jemandem wegen Hautfarbe oder Geschlecht eine Stelle verweigert, verletzt das die Rechtsgleichheit und das Diskriminierungsverbot (Art. 8 BV). Es geht hier nicht um Meinungsäusserung, Niederlassung oder Bildung, sondern um die ungleiche Behandlung aufgrund persönlicher Merkmale.","en":"Refusing someone a job because of their skin colour or sex violates equality before the law and the prohibition of discrimination (Art. 8 of the Constitution). This is not about freedom of expression, residence or education, but about unequal treatment based on personal characteristics.","src":[{"label":"Diskriminierungsverbot – Wikipedia","url":"https://de.wikipedia.org/wiki/Diskriminierungsverbot"}]},
  83: {"de":"Erst mit der Einbürgerung erhält man das Schweizer Bürgerrecht und damit die politischen Rechte – die Teilnahme an Wahlen und Abstimmungen auf Bundesebene. Vereinsmitgliedschaft, Wohnungskauf oder freie Arbeitsplatzwahl stehen auch Personen ohne Schweizer Pass offen.","en":"Only through naturalisation does one obtain Swiss citizenship and with it political rights – the right to vote and take part in referendums at the federal level. Joining a club, buying a flat or freely choosing a workplace are open to people without a Swiss passport as well.","src":[{"label":"Schweizer Bürgerrecht – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_B%C3%BCrgerrecht"}]},
  84: {"de":"Der Persönlichkeits- und Datenschutz wird verletzt, wenn private Informationen über eine Person ohne gesetzliche Grundlage oder ohne deren Zustimmung veröffentlicht werden. Ein unsicherer Computer, ein Foto auf öffentlicher Strasse oder ein zulässiger Pressebericht stellen für sich allein noch keine Datenschutzverletzung dar.","en":"Personality and data protection is violated when private information about a person is published without a legal basis or without the person's consent. An insecure computer, a photo taken on a public street, or a permissible press report do not in themselves constitute a data-protection breach.","src":[{"label":"Datenschutz – Wikipedia","url":"https://de.wikipedia.org/wiki/Datenschutz"}]},
  85: {"de":"Die Bundesverfassung verbietet Folter ausdrücklich; das Folterverbot ist absolut und gilt ausnahmslos (Art. 10 BV). Religiöse Zeichen tragen, Spendensammlungen und unbezahlte Tätigkeiten sind dagegen grundsätzlich erlaubt.","en":"The Federal Constitution expressly prohibits torture; the ban is absolute and applies without exception (Art. 10 of the Constitution). Wearing religious symbols, holding fundraising collections and doing unpaid work are, by contrast, generally permitted.","src":[{"label":"Folter – Wikipedia","url":"https://de.wikipedia.org/wiki/Folter"}]},
  86: {"de":"Die Eigentumsgarantie schützt das persönliche Eigentum und ist als Grundrecht in der Bundesverfassung (Art. 26) verankert. Ein Recht auf kostenlose Ernährung, das Halten von Haustieren oder kostenloses Internet ist dagegen nicht verfassungsmässig garantiert.","en":"The guarantee of property protects personal property and is anchored as a fundamental right in the Federal Constitution (Art. 26). A right to free food, to keeping pets, or to free internet is not constitutionally guaranteed.","src":[{"label":"Eigentumsgarantie – Wikipedia","url":"https://de.wikipedia.org/wiki/Eigentumsgarantie"}]},
  87: {"de":"Andere Menschen wegen ihrer Herkunft oder Religion öffentlich zu beschimpfen ist als Rassendiskriminierung strafbar (Art. 261bis StGB). Die Arbeit des Bundesrats zu kritisieren, Velo zu fahren oder religiöse Zeichen zu tragen ist dagegen erlaubt.","en":"Publicly insulting other people because of their origin or religion is punishable as racial discrimination (Art. 261bis of the Criminal Code). Criticising the work of the Federal Council, riding a bicycle, or wearing religious symbols are, by contrast, permitted.","src":[{"label":"Artikel 261bis StGB – Wikipedia","url":"https://de.wikipedia.org/wiki/Artikel_261bis_StGB"}]},
  88: {"de":"In der Schweiz besteht für Schweizer Männer eine allgemeine Wehrpflicht: Sie leisten Militärdienst oder ersatzweise Zivilschutz. Für Frauen ist der Dienst freiwillig, und die Pflicht hängt weder vom Alter von 20 noch vom Beruf ab.","en":"Switzerland has compulsory military service for Swiss men, who serve in the army or alternatively in civil protection. For women service is voluntary, and the duty depends neither on a particular age threshold nor on one's profession.","src":[{"label":"Wehrpflicht – Wikipedia","url":"https://de.wikipedia.org/wiki/Wehrpflicht"}]},
  89: {"de":"Jemandem allein wegen seiner Hautfarbe den Zutritt zu verweigern verletzt das in der Bundesverfassung (Art. 8) verankerte Diskriminierungsverbot, das eine Benachteiligung etwa wegen Herkunft oder Rasse untersagt. Meinungs-, Versammlungs- und Sportfreiheit sind hier nicht betroffen.","en":"Refusing someone entry solely because of their skin colour violates the prohibition of discrimination enshrined in the Federal Constitution (Art. 8), which bans disadvantaging people on grounds such as origin or race. Freedom of expression, assembly or sport is not the relevant right here.","src":[{"label":"Diskriminierungsverbot – Wikipedia","url":"https://de.wikipedia.org/wiki/Diskriminierungsverbot"}]},
  90: {"de":"Nur Männer unterliegen in der Schweiz der allgemeinen Wehrpflicht und müssen bis zu einem bestimmten Alter Militär- oder Zivilschutzdienst leisten. Steuern, Prämien und familiäre oder politische Pflichten gelten dagegen geschlechtsunabhängig.","en":"Only men in Switzerland are subject to compulsory service and must perform military or civil-protection duty up to a certain age. Taxes, insurance premiums and family or political duties, by contrast, apply regardless of gender.","src":[{"label":"Wehrpflicht – Wikipedia","url":"https://de.wikipedia.org/wiki/Wehrpflicht"}]},
  91: {"de":"In einem Rechtsstaat darf der Staat niemanden willkürlich, also grundlos, verhaften und einsperren; Festnahmen brauchen eine gesetzliche Grundlage und richterliche Kontrolle. Gesetze zu kritisieren, Behörden zu hinterfragen oder einer Religion beizutreten sind dagegen erlaubte Freiheitsrechte.","en":"In a state governed by the rule of law, the state may not arbitrarily arrest and imprison anyone without grounds; detention requires a legal basis and judicial oversight. Criticising laws, questioning authorities or joining a religion are, by contrast, protected freedoms.","src":[{"label":"Rechtsstaat – Wikipedia","url":"https://de.wikipedia.org/wiki/Rechtsstaat"}]},
  92: {"de":"Wer in der Schweiz gegen ein Gesetz verstösst, wird durch den Staat strafrechtlich verfolgt und bestraft; Selbstjustiz und Rache durch Opfer sind verboten. Eine Selbstanzeige führt nicht automatisch zur Straffreiheit, und Opfer können sich die Strafe nicht aussuchen.","en":"Anyone who breaks a law in Switzerland is prosecuted and punished by the state; vigilante justice and revenge by victims are forbidden. Turning oneself in does not automatically grant impunity, and victims cannot choose the penalty.","src":[{"label":"Strafe – Wikipedia","url":"https://de.wikipedia.org/wiki/Strafe"}]},
  93: {"de":"Die Schweizerische Bundesverfassung verbietet die Todesstrafe ausdrücklich (Art. 10 Abs. 1, Recht auf Leben). Geld-, Freiheits- und gemeinnützige Strafen sind dagegen zulässige Sanktionen.","en":"The Swiss Federal Constitution expressly prohibits the death penalty (Art. 10 para. 1, the right to life). Fines, prison sentences and community service, by contrast, are permitted sanctions.","src":[{"label":"Todesstrafe – Wikipedia","url":"https://de.wikipedia.org/wiki/Todesstrafe"}]},
  94: {"de":"Das Mietverhältnis ist im Obligationenrecht (OR) geregelt, das als Teil des Zivilrechts Verträge wie die Miete behandelt. Das MWSTG betrifft Steuern, das StGB Straftaten und das SchKG Betreibung und Konkurs.","en":"Renting an apartment is governed by the Code of Obligations (OR), which as part of civil law covers contracts such as leases. The VAT Act concerns taxes, the Criminal Code concerns offences, and the SchKG concerns debt enforcement and bankruptcy.","src":[{"label":"Obligationenrecht – Wikipedia","url":"https://de.wikipedia.org/wiki/Obligationenrecht"}]},
  95: {"de":"Das Zivilgesetzbuch (ZGB) regelt das Personen-, Familien-, Erb- und Sachenrecht – darunter Eheschliessung und Scheidung. Firmengründungen fallen ins Obligationenrecht, Tötungsdelikte ins Strafgesetzbuch und Staatsverträge ins Völkerrecht.","en":"The Civil Code (ZGB) governs the law of persons, family, inheritance and property, including marriage and divorce. Founding companies falls under the Code of Obligations, homicide under the Criminal Code, and treaties under international law.","src":[{"label":"Schweizerisches Zivilgesetzbuch – Wikipedia","url":"https://de.wikipedia.org/wiki/Zivilgesetzbuch"}]},
  96: {"de":"Ob jemand ins Gefängnis muss, regelt das Strafgesetzbuch (StGB), das Straftaten und ihre Strafen festlegt. OR und ZGB betreffen das Zivilrecht, das SchKG die Schuldbetreibung.","en":"Whether someone goes to prison is governed by the Criminal Code (StGB), which defines offences and their penalties. The OR and ZGB concern civil law, and the SchKG concerns debt enforcement.","src":[{"label":"Schweizerisches Strafgesetzbuch – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerisches_Strafgesetzbuch"}]},
  97: {"de":"Die Richterinnen und Richter des Bundesgerichts werden von der Vereinigten Bundesversammlung, also dem gesamten Bundesparlament (National- und Ständerat), gewählt. Weder die Kantonsparlamente noch der Bundesrat ernennen sie, und es gibt kein gewöhnliches Bewerbungsverfahren.","en":"Federal Supreme Court judges are elected by the United Federal Assembly, i.e. the full federal parliament (National Council and Council of States). Neither the cantonal parliaments nor the Federal Council appoints them, and there is no ordinary job-application procedure.","src":[{"label":"Bundesgericht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesgericht_(Schweiz)"}]},
  98: {"de":"Grundsätzlich dürfen Schweizer Bürgerinnen und Bürger nicht ohne ihre Zustimmung ausgeliefert werden (Art. 25 Bundesverfassung). Eine Ausnahme bilden Überstellungen an internationale Gerichte, vor denen sie sich für schwere Verbrechen verantworten müssen.","en":"In principle, Swiss citizens may not be extradited without their consent (Art. 25 of the Federal Constitution). An exception exists for surrender to international courts, before which they may have to answer for serious crimes.","src":[{"label":"Bundesverfassung Art. 25 – Fedlex","url":"https://www.fedlex.admin.ch/eli/cc/1999/404/de#art_25"}]},
  99: {"de":"Die individuelle Steuerbelastung richtet sich nach dem steuerbaren Einkommen und Vermögen einer Person; je höher diese sind, desto mehr Steuern fallen an. Parteizugehörigkeit, Nationalität oder ein Behördenamt spielen dabei keine Rolle.","en":"Individual tax liability depends on a person's taxable income and assets; the higher these are, the more tax is owed. Party membership, nationality or holding public office play no role.","src":[{"label":"Einkommensteuer (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Einkommensteuer_(Schweiz)"}]},
  100: {"de":"Der Regierungsrat des Kantons Zürich, die Kantonsregierung, besteht aus 7 Mitgliedern. Die Zahl 180 entspricht dem Kantonsrat (Parlament), nicht der Regierung.","en":"The Regierungsrat of the Canton of Zürich, the cantonal government, has 7 members. The number 180 refers to the Kantonsrat (parliament), not the government.","src":[{"label":"Regierungsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Regierungsrat_(Z%C3%BCrich)"}]},
  101: {"de":"Die Baudirektion ist eine der sieben Direktionen des Kantons Zürich; jede wird von einem Regierungsratsmitglied geführt. Tourismus-, Ernährungs- und Militärdirektion existieren so nicht.","en":"The Baudirektion (building/construction directorate) is one of the canton's seven directorates, each led by a member of the Regierungsrat. There are no directorates for tourism, nutrition or military affairs.","src":[{"label":"Regierungsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Regierungsrat_(Z%C3%BCrich)"}]},
  102: {"de":"Die Exekutive der Stadt Zürich heisst Stadtrat. Nationalrat und Bundesrat sind Bundesorgane, der Regierungsrat ist die Exekutive des Kantons, nicht der Stadt.","en":"The executive of the city of Zürich is called the Stadtrat. The Nationalrat and Bundesrat are federal bodies, and the Regierungsrat is the cantonal (not city) executive.","src":[{"label":"Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Z%C3%BCrich"}]},
  103: {"de":"Das Bildungswesen, einschliesslich der Organisation der Universität, ist Sache der Kantone. Verträge mit der EU, die Bundesverwaltung und die Armee sind dagegen Bundesaufgaben.","en":"Education, including running the university, is a cantonal responsibility. Treaties with the EU, the federal administration and the army are by contrast federal matters.","src":[{"label":"Universität Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Universit%C3%A4t_Z%C3%BCrich"}]},
  104: {"de":"Der Kanton Zürich ist in 12 Bezirke gegliedert (z. B. Zürich, Winterthur, Bülach, Uster, Horgen).","en":"The Canton of Zürich is divided into 12 districts (Bezirke), such as Zürich, Winterthur, Bülach, Uster and Horgen.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  105: {"de":"Mit einer Petition kann sich jede Person an die Behörden wenden, auch ohne Schweizer Bürgerrecht. Referendum, Regierungssitz und parlamentarische Anträge sind hingegen Stimmberechtigten bzw. gewählten Mitgliedern vorbehalten.","en":"Anyone may address the authorities through a petition, even without Swiss citizenship. A referendum, a seat in government and parliamentary motions are by contrast reserved for eligible voters or elected members.","src":[{"label":"Petitionsrecht – Wikipedia","url":"https://de.wikipedia.org/wiki/Petitionsrecht"}]},
  106: {"de":"Die Regierung des Kantons Zürich, der Regierungsrat, zählt 7 Mitglieder, die je eine Direktion leiten.","en":"The government of the Canton of Zürich, the Regierungsrat, has 7 members, each heading one directorate.","src":[{"label":"Regierungsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Regierungsrat_(Z%C3%BCrich)"}]},
  107: {"de":"Die Kantone sind vor allem für ihre eigene Verwaltung und ihre kantonalen Gesetze zuständig. Aussenpolitik, Landesverteidigung sowie Geld- und Zollpolitik liegen beim Bund.","en":"The cantons are mainly responsible for running their own administration and for cantonal laws. Foreign policy, national defence and monetary and customs policy lie with the federal government.","src":[{"label":"Kanton (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_(Schweiz)"}]},
  108: {"de":"Der Kantonsrat des Kantons Zürich wird alle 4 Jahre gewählt; dies entspricht der üblichen Amtsdauer der Legislative.","en":"The Kantonsrat of the Canton of Zürich is elected every 4 years, the standard term of office for the legislature.","src":[{"label":"Kantonsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kantonsrat_(Z%C3%BCrich)"}]},
  109: {"de":"Die Exekutive des Kantons Zürich heisst Regierungsrat. Der Ständerat ist ein Bundesorgan, und ein Landammann leitet die Regierung nur in einigen anderen Kantonen.","en":"The executive of the Canton of Zürich is called the Regierungsrat. The Ständerat is a federal body, and a Landammann heads the government only in some other cantons.","src":[{"label":"Regierungsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Regierungsrat_(Z%C3%BCrich)"}]},
  110: {"de":"Das Zürcher Wappen ist diagonal (schräg) geteilt: oben rechts weiss, unten links blau. Die senkrechten oder Querbalken-Varianten entsprechen anderen Kantonen.","en":"The Zürich coat of arms is divided diagonally: white in the upper right and blue in the lower left. The vertical or horizontal-bar variants belong to other cantons.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  111: {"de":"Wie jeder Vollkanton stellt Zürich 2 Mitglieder im Ständerat. Halbkantone hätten nur einen Sitz.","en":"Like every full canton, Zürich sends 2 members to the Ständerat. Half-cantons would have only one seat.","src":[{"label":"Ständerat – Wikipedia","url":"https://de.wikipedia.org/wiki/St%C3%A4nderat"}]},
  112: {"de":"Das Parlament des Kantons Zürich heisst Kantonsrat; er ist die gesetzgebende Behörde und zählt 180 Mitglieder. 'Landtag' und 'Grosser Rat' sind Bezeichnungen anderer Kantone bzw. Länder, und der Regierungsrat ist die Exekutive (Regierung), nicht das Parlament.","en":"The parliament of the Canton of Zürich is called the Kantonsrat; it is the legislative body with 180 members. 'Landtag' and 'Grosser Rat' are names used in other cantons or countries, and the Regierungsrat is the executive (government), not the parliament.","src":[{"label":"Kantonsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kantonsrat_(Z%C3%BCrich)"}]},
  113: {"de":"Die sieben Mitglieder des Zürcher Regierungsrats werden direkt vom Volk im Majorzverfahren gewählt, nicht vom Parlament oder von Parteien ernannt. Diese Direktwahl durch die Stimmberechtigten besteht im Kanton Zürich seit 1869.","en":"The seven members of the Zürich Regierungsrat are elected directly by the people using a majority (Majorz) system, not appointed by parties or chosen by parliament. This direct election by voters has existed in the canton since 1869.","src":[{"label":"Regierungsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Regierungsrat_(Z%C3%BCrich)"}]},
  114: {"de":"Im Kanton Zürich stellt das kantonale Strassenverkehrsamt die Führerausweise aus; es ist die zuständige kantonale Behörde für Fahrzeuge und Fahrberechtigungen. Die Gemeinde, Verkehrsverbände oder die Polizei sind dafür nicht verantwortlich.","en":"In the Canton of Zürich the cantonal road traffic office (Strassenverkehrsamt) issues driving licences; it is the responsible cantonal authority for vehicles and driving permits. The municipality, transport associations and the police are not in charge of this.","src":[{"label":"Strassenverkehrsamt – Wikipedia","url":"https://de.wikipedia.org/wiki/Strassenverkehrsamt"}]},
  115: {"de":"Die Zulassung von Motorfahrzeugen zum Verkehr (Einlösen, Fahrzeugausweis und Kontrollschilder) erfolgt durch das kantonale Strassenverkehrsamt. Autogaragen, Gemeinde oder Verkehrspolizei haben diese Kompetenz nicht.","en":"Registering motor vehicles for road use (licensing, vehicle registration document and number plates) is done by the cantonal road traffic office (Strassenverkehrsamt). Car dealerships, the municipality or the traffic police do not have this authority.","src":[{"label":"Strassenverkehrsamt – Wikipedia","url":"https://de.wikipedia.org/wiki/Strassenverkehrsamt"}]},
  116: {"de":"Die 180 Mitglieder des Kantonsrats werden durch Wahlen bestimmt, nämlich vom Volk im Proporzverfahren in den Wahlkreisen. Sie werden weder von der Regierung ernannt noch vom Bund oder den Ständeräten bestimmt.","en":"The 180 members of the Kantonsrat are determined by elections, namely by the people through proportional representation in the electoral districts. They are neither appointed by the government nor chosen by the federal level or the Council of States members.","src":[{"label":"Kantonsrat (Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kantonsrat_(Z%C3%BCrich)"}]},
  117: {"de":"An der Gemeindeversammlung entscheiden die Stimmbürgerinnen und Stimmbürger direkt über kommunale Angelegenheiten wie das Budget, die Rechnung oder den Steuerfuss. Nationale Gesetze werden dort nicht beschlossen, das ist Sache des Bundes.","en":"At the municipal assembly (Gemeindeversammlung) the eligible voters decide directly on local matters such as the budget, the accounts or the tax rate. National laws are not passed there; that is the responsibility of the federal level.","src":[{"label":"Gemeindeversammlung – Wikipedia","url":"https://de.wikipedia.org/wiki/Gemeindeversammlung"}]},
  118: {"de":"In der Stadt Zürich wird der Gemeinderat – das Stadtparlament (Legislative) mit 125 Mitgliedern – direkt vom Volk (den Stimmberechtigten) im Proporzverfahren gewählt. Die Exekutive der Stadt ist der Stadtrat. Kantonsrat, Regierungsrat und Bezirksrat treffen diese Wahl nicht.","en":"In the city of Zürich the Gemeinderat – the city parliament (legislative body) with 125 members – is elected directly by the people (the eligible voters) using proportional representation. The city's executive is the Stadtrat. The Kantonsrat, Regierungsrat and Bezirksrat do not make this choice.","src":[{"label":"Gemeinderat (Stadt Zürich) – Wikipedia","url":"https://de.wikipedia.org/wiki/Gemeinderat_(Stadt_Z%C3%BCrich)"}]},
  119: {"de":"Die Volksschule, insbesondere die Primarschule, ist eine zentrale Aufgabe der Zürcher Gemeinden. Autobahnen (Bund), das Militär (Bund) und der Verkauf von Versicherungen (privat) gehören nicht zu den Gemeindeaufgaben.","en":"Compulsory schooling, in particular primary school, is a core task of Zürich municipalities. Motorways (federal), the military (federal) and selling insurance (private business) are not municipal responsibilities.","src":[{"label":"Volksschule – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksschule"}]},
  120: {"de":"Die Baubewilligung für ein Einfamilienhaus wird von der Gemeinde erteilt, die als örtliche Baubehörde das Baugesuch prüft. Nachbarn, ein Quartierkomitee oder die Architektin können keine rechtsgültige Bewilligung ausstellen.","en":"The building permit for a single-family house is granted by the municipality, which acts as the local building authority and reviews the application. Neighbours, a neighbourhood committee or the architect cannot issue a legally valid permit.","src":[{"label":"Baubewilligung – Wikipedia","url":"https://de.wikipedia.org/wiki/Baubewilligung"}]},
  121: {"de":"Die Gemeinden sind unter anderem für die lokale Raumplanung zuständig, etwa für Nutzungs- und Zonenpläne auf ihrem Gebiet. Aussenpolitik und Militär sind Bundesaufgaben, und private Feste organisieren die Gemeinden nicht.","en":"Municipalities are responsible, among other things, for local spatial planning, such as land-use and zoning plans within their territory. Foreign policy and the military are federal tasks, and municipalities do not organise private celebrations.","src":[{"label":"Raumplanung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Raumplanung_in_der_Schweiz"}]},
  122: {"de":"Bei Abstimmungen und Wahlen zählt das Wahlbüro (auch Wahl- und Abstimmungsbüro) der Gemeinde die Stimmzettel aus. Es besteht meist aus Stimmberechtigten, die für diese Aufgabe eingesetzt werden; Militär oder Polizei sind dafür nicht zuständig.","en":"At votes and elections the municipal electoral office (Wahlbüro) counts the ballots. It usually consists of eligible voters appointed for this task; the military or the police are not responsible for it.","src":[{"label":"Volksabstimmung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksabstimmung_(Schweiz)"}]},
  123: {"de":"Politische Mitbestimmung auf Gemeindeebene erfolgt vor allem durch die Teilnahme an Wahlen und Abstimmungen (sowie an der Gemeindeversammlung). Steuern zahlen, Vereinsarbeit oder der Besuch von Volksfesten sind keine formellen politischen Entscheidungen.","en":"Political participation at the municipal level happens above all by taking part in elections and votes (and in the municipal assembly). Paying taxes, being active in clubs or attending public festivals are not formal political decisions.","src":[{"label":"Politische Rechte (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Rechte_(Schweiz)"}]},
  124: {"de":"Der Stadtrat ist die Exekutive der Stadt Zürich: Er leitet die Stadtverwaltung und legt die Ziele des öffentlichen Handelns fest. Die Stadtkanzlei unterstützt ihn nur administrativ, die Einwohnerkontrolle führt das Personenregister, und die Stimmberechtigten wählen die Behörden, leiten die Verwaltung aber nicht.","en":"The Stadtrat is the executive of the City of Zürich: it runs the city administration and sets the goals of public action. The Stadtkanzlei only provides administrative support, the residents' registration office keeps the register of inhabitants, and the citizens elect the authorities but do not run the administration themselves.","src":[{"label":"Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Z%C3%BCrich"}]},
  125: {"de":"Die Einwohnerkontrolle (Führen des Einwohnerregisters, An- und Abmeldungen) ist eine typische kommunale Aufgabe. Fachhochschulen sind kantonal/national geregelt, die Geldpolitik ist Sache des Bundes bzw. der Nationalbank, und der Zivildienst ist eine Bundesaufgabe.","en":"The residents' registration office (keeping the register of inhabitants, processing arrivals and departures) is a typical municipal task. Universities of applied sciences are regulated at cantonal/national level, monetary policy is a federal matter handled by the National Bank, and civilian service is a federal responsibility.","src":[{"label":"Einwohnerkontrolle – Wikipedia","url":"https://de.wikipedia.org/wiki/Einwohnerkontrolle"}]},
  126: {"de":"Der Kanton Zürich zählt 160 politische Gemeinden, also liegt die Zahl zwischen 150 und 170. Die übrigen Spannen sind deutlich zu tief oder zu hoch.","en":"The Canton of Zürich has 160 political municipalities, so the number lies between 150 and 170. The other ranges are clearly too low or too high.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  127: {"de":"In den meisten Zürcher Gemeinden heisst die oberste Repräsentantin oder der oberste Repräsentant Gemeindepräsidentin bzw. Gemeindepräsident (in der Stadt Zürich Stadtpräsident/in). Der Titel «Gemeindeammann» ist in anderen Kantonen üblich, nicht im Kanton Zürich.","en":"In most Zürich municipalities the highest representative is called the Gemeindepräsident(in) (mayor); in the City of Zürich the title is Stadtpräsident(in). The title 'Gemeindeammann' is used in other cantons, not in the Canton of Zürich.","src":[{"label":"Gemeindepräsident – Wikipedia","url":"https://de.wikipedia.org/wiki/Gemeindepr%C3%A4sident"}]},
  128: {"de":"In der Steuererklärung legt die steuerpflichtige Person ihre finanzielle Situation (Einkommen, Vermögen, Abzüge) gegenüber der Steuerbehörde offen, damit diese die Steuer berechnen kann. Sie ist also keine Anleitung zum Ausfüllen und betrifft nicht nur Lotteriegewinne.","en":"In the tax return the taxpayer discloses their financial situation (income, assets, deductions) to the tax authority so that it can assess the tax owed. It is therefore not a set of instructions on how to fill in forms, nor is it limited to lottery winnings.","src":[{"label":"Steuererklärung – Wikipedia","url":"https://de.wikipedia.org/wiki/Steuererkl%C3%A4rung"}]},
  129: {"de":"Ein Arbeitszeugnis ist eine vom Arbeitgeber ausgestellte Urkunde, die Art und Dauer der Tätigkeit sowie Leistung und Verhalten der Arbeitnehmerin oder des Arbeitnehmers bescheinigt. Es wird also vom Arbeitgeber verfasst, nicht vom Arbeitnehmer, und ist kein Gesamtarbeitsvertrag.","en":"A work reference (Arbeitszeugnis) is a document issued by the employer that certifies the nature and duration of the employment as well as the employee's performance and conduct. It is written by the employer, not the employee, and is not a collective labour agreement.","src":[{"label":"Arbeitszeugnis – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitszeugnis"}]},
  130: {"de":"In der Schweiz ist die obligatorische Krankenpflegeversicherung (Grundversicherung) für alle Wohnhaften Pflicht. Zusatzversicherungen, Zahn- oder Alternativmedizin-Versicherungen sind dagegen freiwillig.","en":"In Switzerland the compulsory basic health insurance (Grundversicherung) is mandatory for everyone resident in the country. Supplementary insurance and dental or alternative-medicine cover, by contrast, are voluntary.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  131: {"de":"Erwerbstätige – Arbeitnehmende wie Selbständigerwerbende – mit Kindern haben Anspruch auf Familienzulagen (Kinder- und Ausbildungszulagen), die den finanziellen Aufwand für Kinder mildern. «Kinderbegünstigung», «Elternentlastung» und «Finanzhilfe» sind keine korrekten Bezeichnungen dieser Leistung.","en":"Working people with children — both employees and the self-employed — are entitled to family allowances (child and education allowances), which help offset the cost of raising children. The other terms are not the correct names for this benefit.","src":[{"label":"Familienzulage – Wikipedia","url":"https://de.wikipedia.org/wiki/Familienzulage"}]},
  132: {"de":"Der Zivildienst ist ein Ersatz für den Militärdienst: Wer den Militärdienst aus Gewissensgründen nicht leisten kann, verrichtet stattdessen einen längeren zivilen Dienst zugunsten der Gemeinschaft. Er ist also weder freiwillig im engeren Sinn noch für alle obligatorisch.","en":"Civilian service is a substitute for military service: those who cannot perform military service for reasons of conscience instead carry out a longer civilian service for the benefit of the community. It is therefore neither voluntary in the strict sense nor compulsory for everyone.","src":[{"label":"Zivildienst in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Zivildienst_in_der_Schweiz"}]},
  133: {"de":"Bei der obligatorischen Grundversicherung kann man die Krankenkasse frei wählen, und die Kassen müssen jede Person aufnehmen. Die Leistungen der Grundversicherung sind gesetzlich für alle Kassen gleich festgelegt, eine Krankenkasse ist nicht freiwillig, und der Kanton teilt niemandem eine Kasse zu.","en":"For the compulsory basic insurance you can freely choose your health insurer, and insurers must accept everyone. The benefits of the basic insurance are fixed by law and identical across all insurers, having insurance is not optional, and the canton does not assign anyone to a particular insurer.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  134: {"de":"Bei eidgenössischen (nationalen) Abstimmungen und Wahlen ist das Stimm- und Wahlrecht in der Schweiz dem Schweizer Bürgerrecht vorbehalten; Personen ohne Schweizer Pass dürfen auf nationaler Ebene gar nicht abstimmen. Ein Mitwirken bei einzelnen Vorlagen oder zu bestimmten Terminen ist nicht möglich.","en":"For federal (national) votes and elections, the right to vote in Switzerland is reserved for Swiss citizens; people without a Swiss passport cannot vote at the national level at all. Participation in selected proposals or on particular dates is not possible.","src":[{"label":"Politische Rechte (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Rechte_(Schweiz)"}]},
  135: {"de":"Die Nummer 117 ist in der Schweiz der Polizeinotruf. Andere Notnummern sind etwa 118 (Feuerwehr), 144 (Sanität) und 112 (allgemeiner Notruf); für Pannen wählt man 140.","en":"In Switzerland the number 117 is the police emergency line. Other emergency numbers include 118 (fire brigade), 144 (ambulance) and 112 (general emergency); for vehicle breakdowns you dial 140.","src":[{"label":"Notruf – Wikipedia","url":"https://de.wikipedia.org/wiki/Notruf"}]},
  136: {"de":"Die Schweizer Sozialversicherungen sichern die Bevölkerung gegen typische Lebensrisiken wie Krankheit, Unfall, Invalidität, Alter und Arbeitslosigkeit ab. Schutz vor Einbruch, Hochwasser oder Kommunikationsmissbrauch gehört dagegen zu Privatversicherungen oder anderen Rechtsgebieten, nicht zum Sozialversicherungssystem.","en":"Switzerland's social insurance system protects the population against major life risks such as illness, accident, disability, old age and unemployment. Protection against burglary, flooding or communication abuse belongs to private insurance or other areas of law, not to the social insurance system.","src":[{"label":"Sozialversicherungen (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Sozialversicherungen_(Schweiz)"}]},
  137: {"de":"Bei Stellenverlust greift die obligatorische Arbeitslosenversicherung (ALV), die einen Teil des bisherigen Lohns als Taggeld ersetzt. Zahnverlust, Velodiebstahl oder Scheidung sind keine durch eine Sozialversicherung gedeckten Risiken.","en":"If you lose your job, the mandatory unemployment insurance (ALV) steps in and replaces part of your former wage as a daily allowance. Losing a tooth, having your bike stolen or getting divorced are not risks covered by a social insurance.","src":[{"label":"Sozialversicherungen (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Sozialversicherungen_(Schweiz)"}]},
  138: {"de":"Die AHV/IV (Alters-, Hinterlassenen- und Invalidenversicherung) ist eine zentrale Schweizer Sozialversicherung und bildet die erste Säule der Altersvorsorge. Schul-, Freizeit- oder Scheidungsvorsorge sind keine Sozialversicherungen.","en":"The AHV/IV (old-age, survivors' and disability insurance) is a core Swiss social insurance and forms the first pillar of old-age provision. School, leisure or divorce 'provision' are not social insurances.","src":[{"label":"Alters- und Hinterlassenenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Alters-_und_Hinterlassenenversicherung"}]},
  139: {"de":"Die erste Säule der Altersvorsorge ist die AHV (Alters-, Hinterlassenen- und Invalidenversicherung); sie ist obligatorisch und soll den Existenzbedarf decken. Die Pensionskasse ist die zweite Säule, die private Vorsorge die dritte.","en":"The first pillar of old-age provision is the AHV (old-age, survivors' and disability insurance); it is mandatory and is meant to cover basic living needs. The pension fund is the second pillar and private provision the third.","src":[{"label":"Drei-Säulen-System (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Drei-S%C3%A4ulen-System_(Schweiz)"}]},
  140: {"de":"Die zweite Säule ist die berufliche Vorsorge, also die Pensionskasse (BVG). Sie ergänzt die AHV und soll zusammen mit ihr den gewohnten Lebensstandard im Alter sichern; sie wird von Arbeitgeber und Arbeitnehmer gemeinsam finanziert.","en":"The second pillar is occupational provision, i.e. the pension fund (BVG). It supplements the AHV and, together with it, is meant to maintain one's accustomed standard of living in old age; it is funded jointly by employer and employee.","src":[{"label":"Drei-Säulen-System (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Drei-S%C3%A4ulen-System_(Schweiz)"}]},
  141: {"de":"Die dritte Säule ist die freiwillige private Vorsorge, mit der man individuell zusätzlich fürs Alter spart (z. B. gebundene Vorsorge 3a). Invalidenversicherung und Erwerbsersatz gehören zur ersten Säule.","en":"The third pillar is voluntary private provision, through which individuals save extra for old age on their own (e.g. tied pension 3a). Disability insurance and income compensation belong to the first pillar.","src":[{"label":"Drei-Säulen-System (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Drei-S%C3%A4ulen-System_(Schweiz)"}]},
  142: {"de":"Amnesty International ist eine weltweite Nichtregierungsorganisation, die sich für die Einhaltung der Menschenrechte einsetzt, etwa gegen Folter, Todesstrafe und die Inhaftierung von Gewissensgefangenen. Klimaschutz, Artenvielfalt und Tierwohl sind Anliegen anderer Organisationen.","en":"Amnesty International is a worldwide non-governmental organisation campaigning for respect of human rights, for example against torture, the death penalty and the imprisonment of prisoners of conscience. Climate protection, biodiversity and animal welfare are the concerns of other organisations.","src":[{"label":"Amnesty International – Wikipedia","url":"https://de.wikipedia.org/wiki/Amnesty_International"}]},
  143: {"de":"Gewerkschaften vertreten die Interessen der Arbeitnehmenden, etwa bei Löhnen, Arbeitszeiten und Arbeitsbedingungen, und handeln Gesamtarbeitsverträge aus. Kirchen, Spitäler und Schulen haben andere Aufgaben.","en":"Trade unions represent the interests of employees, for instance on wages, working hours and working conditions, and negotiate collective labour agreements. Churches, hospitals and schools have other functions.","src":[{"label":"Gewerkschaft – Wikipedia","url":"https://de.wikipedia.org/wiki/Gewerkschaft"}]},
  144: {"de":"Mit der seit 2002 geltenden Fristenregelung darf eine Frau in den ersten zwölf Wochen der Schwangerschaft straflos und frei über einen Abbruch entscheiden (nach einem Gespräch und schriftlichem Gesuch). Eine Erlaubnis des Ehemannes ist nicht nötig, und ein generelles Verbot besteht nicht.","en":"Under the time-limit rule in force since 2002, a woman may freely and without penalty decide on an abortion during the first twelve weeks of pregnancy (after counselling and a written request). No permission from the husband is required, and there is no general ban.","src":[{"label":"Fristenregelung – Wikipedia","url":"https://de.wikipedia.org/wiki/Fristenregelung"}]},
  145: {"de":"AHV steht für Alters- und Hinterlassenenversicherung. Sie zahlt Renten im Alter sowie an Hinterbliebene (Witwen, Witwer, Waisen) und ist für alle in der Schweiz wohnhaften oder erwerbstätigen Personen obligatorisch.","en":"AHV stands for old-age and survivors' insurance (Alters- und Hinterlassenenversicherung). It pays pensions in old age and to surviving dependants (widows, widowers, orphans) and is mandatory for everyone living or working in Switzerland.","src":[{"label":"Alters- und Hinterlassenenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Alters-_und_Hinterlassenenversicherung"}]},
  146: {"de":"Familien in der Schweiz erhalten Familienzulagen, insbesondere Kinderzulagen (und Ausbildungszulagen für ältere Kinder in Ausbildung), die einen Teil der Kosten für Kinder ausgleichen. Gratis-Bahnfahrten oder eine pauschale Familienunterstützung gibt es nicht.","en":"Families in Switzerland receive family allowances, in particular child allowances (and training allowances for older children in education), which offset part of the cost of raising children. There are no free train rides or blanket family support payments.","src":[{"label":"Familienzulage – Wikipedia","url":"https://de.wikipedia.org/wiki/Familienzulage"}]},
  147: {"de":"Die AHV ist für alle in der Schweiz wohnhaften oder erwerbstätigen Personen obligatorisch und bildet die Grundlage der Altersvorsorge. Eine 'Jugend-', 'Lebens-' oder 'Geburtenversicherung' als obligatorische Sozialversicherung gibt es nicht.","en":"The AHV is mandatory for everyone living or working in Switzerland and forms the basis of old-age provision. There is no compulsory social insurance called 'youth', 'life' or 'birth' insurance.","src":[{"label":"Alters- und Hinterlassenenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Alters-_und_Hinterlassenenversicherung"}]},
  148: {"de":"Wer mit der Steuerveranlagung nicht einverstanden ist, kann innert Frist schriftlich Einsprache bei der Steuerbehörde erheben und seine Einwände begründen. Die Steuer einfach nur halb zu bezahlen, die Rechnung zurückzuschicken oder die Polizei einzuschalten ist nicht das vorgesehene Verfahren.","en":"Anyone who disagrees with their tax assessment can lodge a written objection with the tax authority within the deadline and state their reasons. Simply paying half, returning the bill, or going to the police is not the proper procedure.","src":[{"label":"Einsprache – Wikipedia","url":"https://de.wikipedia.org/wiki/Einsprache"}]},
  149: {"de":"Der Staat entlastet Familien unter anderem über Steuerabzüge, etwa Kinderabzüge und Abzüge für Betreuungskosten, wodurch das steuerbare Einkommen sinkt. Gratis-Internet oder verbilligte Lebensmittel gehören nicht zu den staatlichen Familienleistungen.","en":"The state supports families partly through tax deductions, such as child deductions and deductions for childcare costs, which reduce taxable income. Free internet or cheaper groceries are not state family benefits.","src":[{"label":"Familienpolitik – Wikipedia","url":"https://de.wikipedia.org/wiki/Familienpolitik"}]},
  150: {"de":"Mit Steuergeldern finanziert der Staat öffentliche Aufgaben wie die Schulen (Volksschule). Arztpraxen, Kinos und Hotels sind dagegen private Betriebe und werden nicht aus Steuern bezahlt.","en":"With tax revenue the state finances public services such as schools (public schooling). Doctors' practices, cinemas and hotels, by contrast, are private businesses and are not funded from taxes.","src":[{"label":"Steuer – Wikipedia","url":"https://de.wikipedia.org/wiki/Steuer"}]},
  151: {"de":"Die Invalidenversicherung (IV) ist eine der staatlichen Sozialversicherungen der Schweiz und sichert Menschen bei Invalidität ab. Die übrigen genannten Versicherungen sind private Sach- oder Schadenversicherungen, keine Sozialversicherungen.","en":"The disability insurance (IV) is one of Switzerland's state social insurance schemes, protecting people in the event of disability. The other options listed are private property or casualty insurances, not social insurance.","src":[{"label":"Invalidenversicherung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Invalidenversicherung_(Schweiz)"}]},
  152: {"de":"Die Arbeitslosenversicherung (ALV) gehört zu den obligatorischen Sozialversicherungen, deren Beiträge dem Lohn der Angestellten direkt abgezogen werden (zusammen mit AHV/IV/EO usw.). Die anderen aufgeführten Versicherungen existieren so nicht als Lohnabzug.","en":"Unemployment insurance (ALV) is one of the compulsory social insurances whose contributions are deducted directly from employees' wages (along with AHV/IV/EO etc.). The other insurances listed do not exist as wage deductions.","src":[{"label":"Arbeitslosenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitslosenversicherung"}]},
  153: {"de":"RAV steht für Regionales Arbeitsvermittlungszentrum, die staatliche Anlaufstelle für Arbeitslose, die bei der Stellensuche berät und die Bemühungen kontrolliert. Es ist keine Rechtsstelle, kein Institut und keine Rentenanstalt.","en":"RAV stands for Regionales Arbeitsvermittlungszentrum (Regional Employment Centre), the state contact point for the unemployed that advises on job seeking and monitors their efforts. It is not a legal office, institute or pension provider.","src":[{"label":"Regionales Arbeitsvermittlungszentrum – Wikipedia","url":"https://de.wikipedia.org/wiki/Regionales_Arbeitsvermittlungszentrum"}]},
  154: {"de":"Die Abkürzung IV steht für Invalidenversicherung, eine der schweizerischen Sozialversicherungen, die bei Invalidität existenzsichernde Leistungen erbringt. Die anderen Auflösungen der Abkürzung sind frei erfunden.","en":"The abbreviation IV stands for Invalidenversicherung (disability insurance), one of Switzerland's social insurance schemes that provides subsistence benefits in the event of disability. The other expansions of the abbreviation are made up.","src":[{"label":"Invalidenversicherung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Invalidenversicherung_(Schweiz)"}]},
  155: {"de":"In der Schweiz besteht eine Krankenversicherungspflicht: Alle Einwohnerinnen und Einwohner müssen sich für die Grundversicherung bei einer Krankenkasse versichern. Die Pflicht gilt nicht nur für Arbeitnehmende oder bestimmte Altersgruppen.","en":"Switzerland has compulsory health insurance: all residents must take out basic insurance with a health insurer. The obligation is not limited to employees or to certain age groups.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  156: {"de":"Bei einem schweren Arbeitsunfall übernimmt die obligatorische Berufsunfallversicherung (Unfallversicherung nach UVG) die Spital- und Heilungskosten. Diese Versicherung wird für Angestellte von der Arbeitgeberin abgeschlossen, zahlt aber als Versicherung selbst die Kosten.","en":"In the case of a serious occupational accident, the compulsory occupational accident insurance (accident insurance under the UVG) covers the hospital and treatment costs. The employer takes out this insurance for employees, but it is the insurer that actually pays the costs.","src":[{"label":"Unfallversicherung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Unfallversicherung_(Schweiz)"}]},
  157: {"de":"Die Krankenversicherung (Grundversicherung) ist in der Schweiz für alle obligatorisch. Eine private Haftpflicht- oder Vermögensversicherung ist freiwillig, und eine «Arbeitsversicherung» gibt es in dieser Form nicht.","en":"Health insurance (basic coverage) is compulsory for everyone in Switzerland. Private liability or asset insurance is voluntary, and an 'employment insurance' in this form does not exist.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  158: {"de":"BAG ist die Abkürzung für das Bundesamt für Gesundheit, die für die nationale Gesundheitspolitik zuständige Bundesbehörde. Die anderen Auflösungen sind erfunden.","en":"BAG is the abbreviation for the Bundesamt für Gesundheit (Federal Office of Public Health), the federal authority responsible for national health policy. The other expansions are invented.","src":[{"label":"Bundesamt für Gesundheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesamt_f%C3%BCr_Gesundheit"}]},
  159: {"de":"Die Nummer 144 ist in der Schweiz der Sanitätsnotruf (Ambulanz) für medizinische Notfälle. Die Feuerwehr erreicht man unter 118, die Polizei unter 117.","en":"In Switzerland the number 144 is the medical emergency call (ambulance) for medical emergencies. The fire brigade is reached on 118 and the police on 117.","src":[{"label":"Notruf – Wikipedia","url":"https://de.wikipedia.org/wiki/Notruf"}]},
  160: {"de":"In der Schweiz gilt eine obligatorische Grundversicherung (KVG) für alle, die hier wohnen. Für Neugeborene muss innerhalb von drei Monaten nach der Geburt eine Krankenversicherung abgeschlossen werden; die Deckung gilt dann rückwirkend ab Geburt.","en":"Switzerland has compulsory basic health insurance (KVG) for everyone living here. For newborns, a policy must be taken out within three months of birth, with coverage then applying retroactively from the date of birth.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  161: {"de":"Die obligatorische Schulzeit (Schulpflicht) dauert in der Schweiz schweizweit elf Jahre, eingerechnet die beiden Kindergarten- bzw. Eingangsjahre. Acht oder dreizehn Jahre umfassen nur Teilabschnitte der Schullaufbahn.","en":"Compulsory schooling in Switzerland lasts eleven years nationwide, including the two kindergarten/entry years. Eight or thirteen years only cover parts of the school career.","src":[{"label":"Bildungssystem in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Bildungssystem_in_der_Schweiz"}]},
  162: {"de":"Über die Klassen- bzw. Schulzuteilung entscheidet die Schule, also die Schulleitung oder die Schulpflege (Schulbehörde der Gemeinde), nicht die Eltern oder die Kinder selbst. Damit werden Klassengrössen und schulorganisatorische Vorgaben sichergestellt.","en":"The placement of a child in a particular class is decided by the school, i.e. the school management or the school board (Schulpflege) of the municipality, not by the parents or the children. This ensures balanced class sizes and proper school organisation.","src":[{"label":"Bildungssystem in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Bildungssystem_in_der_Schweiz"}]},
  163: {"de":"Nach dem Schweizerischen Zivilgesetzbuch sind in erster Linie die Eltern für die Pflege und Erziehung ihrer Kinder verantwortlich (elterliche Sorge). Staat und Schule unterstützen sie dabei, übernehmen die Erziehung aber nicht selbst.","en":"Under the Swiss Civil Code, parents are primarily responsible for the care and upbringing of their children (parental responsibility). The state and schools support them but do not take over this role themselves.","src":[{"label":"Elterliche Sorge – Wikipedia","url":"https://de.wikipedia.org/wiki/Elterliche_Sorge"}]},
  164: {"de":"Obligatorisch ist die Grundschulbildung; die Primarschule ist Teil der für alle verpflichtenden Volksschule. Kindertagesstätte, Maturitätsschule und Weiterbildungskurse sind hingegen freiwillig.","en":"Basic education is compulsory; primary school is part of the mandatory public school system for all children. Day-care, the academic high school (Matura school) and continuing-education courses, by contrast, are voluntary.","src":[{"label":"Bildungssystem in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Bildungssystem_in_der_Schweiz"}]},
  165: {"de":"Während der Schwangerschaft und in den Wochen nach der Geburt gilt ein gesetzlicher Kündigungsschutz (Sperrfrist nach Obligationenrecht); eine in dieser Zeit ausgesprochene Kündigung der Arbeitgeberseite ist nichtig. Pünktlichkeit oder Betriebszugehörigkeit bieten dagegen keinen solchen Schutz.","en":"During pregnancy and in the weeks after childbirth there is statutory protection against dismissal (a blocking period under the Code of Obligations); a dismissal by the employer during this time is void. Punctuality or length of service, by contrast, give no such protection.","src":[{"label":"Kündigungsschutz – Wikipedia","url":"https://de.wikipedia.org/wiki/K%C3%BCndigungsschutz"}]},
  166: {"de":"Gewerkschaften sind Zusammenschlüsse von Arbeitnehmerinnen und Arbeitnehmern, die deren wirtschaftliche und soziale Interessen vertreten, etwa in Lohnverhandlungen. Die Interessen der Arbeitgeber werden dagegen von Arbeitgeber- und Wirtschaftsverbänden vertreten.","en":"Trade unions are associations of employees that represent their economic and social interests, for example in wage negotiations. Employers' interests, by contrast, are represented by employer and business associations.","src":[{"label":"Gewerkschaft – Wikipedia","url":"https://de.wikipedia.org/wiki/Gewerkschaft"}]},
  167: {"de":"Das Arbeitsgericht ist für Streitigkeiten aus dem Arbeitsverhältnis zuständig, etwa bei einer ungerechtfertigten Kündigung. Erbschaftssteuern, Nachbarschaftsstreit oder familiäre Geldsorgen fallen nicht in seinen Bereich.","en":"The labour court is responsible for disputes arising from the employment relationship, such as an unjustified dismissal. Inheritance tax, neighbour disputes or family financial troubles fall outside its remit.","src":[{"label":"Arbeitsgericht – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitsgericht"}]},
  168: {"de":"Bei arbeitsrechtlichen Fragen sind Anwältinnen und Anwälte, Gewerkschaften und die Arbeitsgerichte die richtigen Anlaufstellen. Steuerverwaltung, Polizei, Einwohnerkontrolle oder Kirchgemeinde sind dafür nicht zuständig.","en":"For questions of employment law, lawyers, trade unions and the labour courts are the right places to turn to. The tax office, police, residents' registration office or parish are not responsible for such matters.","src":[{"label":"Arbeitsrecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitsrecht_(Schweiz)"}]},
  169: {"de":"Eine Kündigung sollte beweissicher erfolgen: am besten mit eingeschriebenem Brief oder so, dass der Eingang schriftlich bestätigt wird. So lässt sich belegen, wann das Arbeitsverhältnis korrekt gekündigt wurde; einfaches Fernbleiben oder Abwarten beendet das Arbeitsverhältnis nicht rechtsgültig.","en":"A notice of termination should be given in a way that can be proven, ideally by registered letter or with written confirmation of receipt. This documents when the employment was properly terminated; simply staying away or waiting does not legally end the contract.","src":[{"label":"Obligationenrecht – Wikipedia","url":"https://de.wikipedia.org/wiki/Obligationenrecht"}]},
  170: {"de":"Economiesuisse ist der grösste Dachverband der Schweizer Wirtschaft und vertritt die Interessen der Unternehmen. Angestellte werden von Gewerkschaften vertreten, das Gastgewerbe und das Handwerk von eigenen Branchenverbänden.","en":"Economiesuisse is the largest umbrella organisation of the Swiss economy and represents the interests of companies. Employees are represented by trade unions, while the hospitality trade and crafts have their own sector associations.","src":[{"label":"Economiesuisse – Wikipedia","url":"https://de.wikipedia.org/wiki/Economiesuisse"}]},
  171: {"de":"Im Arbeitsvertrag werden die wesentlichen Bedingungen des Arbeitsverhältnisses festgehalten, unter anderem die Höhe des Lohns. Krankenkasse, Altersrente und Freizeitgestaltung sind dagegen nicht Gegenstand des Arbeitsvertrags.","en":"The employment contract sets out the essential terms of the working relationship, including the amount of the wage. The choice of health insurer, the level of the old-age pension and how one spends one's free time are not part of the employment contract.","src":[{"label":"Arbeitsvertrag – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitsvertrag"}]},
  172: {"de":"Wer zu wenig Lohn erhält, kann den Anspruch zivilrechtlich beim Arbeitsgericht geltend machen, das für Streitigkeiten aus dem Arbeitsverhältnis zuständig ist. Die Polizei (Strafrecht) ist nicht zuständig, und einfaches Fernbleiben von der Arbeit wäre selbst eine Vertragsverletzung.","en":"If you are paid too little, you can pursue the claim through the labour court, which handles disputes arising from employment relationships. The police deal with criminal matters and are not responsible, and simply staying away from work would itself breach the contract.","src":[{"label":"Arbeitsgericht – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitsgericht"}]},
  173: {"de":"Ein Berufsbildungszentrum ist ein Standort, der verschiedene Angebote der beruflichen Bildung bündelt, etwa Berufsfachschulen und überbetriebliche Kurse. Es ist weder eine reine Arbeitsvermittlung noch eine Fachhochschule.","en":"A vocational training centre is a location that brings together various offerings of vocational education, such as vocational schools and inter-company courses. It is neither a job placement agency nor a university of applied sciences.","src":[{"label":"Berufsbildung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Berufsbildung_(Schweiz)"}]},
  174: {"de":"Der 1. August ist der einzige Feiertag, der durch Bundesrecht (Art. 110 Abs. 3 BV) den Sonntagen gleichgestellt und damit für die ganze Schweiz festgelegt ist; er ist seit 1994 landesweit arbeitsfrei. Alle übrigen Feiertage – auch Auffahrt, das in allen Kantonen gilt – werden kantonal geregelt; Karfreitag und der 1. Mai sind dabei nicht überall ein Feiertag.","en":"1 August is the only public holiday established by federal law (Art. 110 para. 3 of the Federal Constitution), putting it on a par with Sundays for the whole of Switzerland; it has been a nationwide day off since 1994. All other holidays – including Ascension Day, which is observed in every canton – are regulated at cantonal level; Good Friday and 1 May are not holidays everywhere.","src":[{"label":"Feiertage in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Feiertage_in_der_Schweiz"}]},
  175: {"de":"Das ordentliche Rentenalter (Referenzalter) der AHV liegt bei 65 Jahren für Frauen und Männer. Mit der Reform AHV 21 wird das Referenzalter der Frauen schrittweise auf 65 angehoben, sodass für beide Geschlechter 65 Jahre gelten.","en":"The ordinary retirement age (reference age) for the AHV old-age pension is 65 for both women and men. Under the AHV 21 reform, women's reference age is being raised step by step to 65, so that 65 applies to both sexes.","src":[{"label":"Alters- und Hinterlassenenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Alters-_und_Hinterlassenenversicherung"}]},
  176: {"de":"Pensionierte zahlen keine Prämien für die Arbeitslosenversicherung, da diese nur auf Erwerbseinkommen erhoben werden und für Personen im Ruhestand keine Arbeitslosigkeit mehr abzusichern ist. Erwerbstätige hingegen entrichten ALV-Beiträge auf ihrem Lohn.","en":"Retirees pay no unemployment insurance contributions, because these are levied only on earned income and there is no unemployment risk to cover for people who have left working life. Employees, by contrast, pay unemployment insurance contributions on their wages.","src":[{"label":"Arbeitslosenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Arbeitslosenversicherung"}]},
  177: {"de":"Das Berufsinformationszentrum (BIZ) bietet Auskünfte und Unterlagen zu Lehrstellen, Berufen und Arbeitswelt für alle Interessierten. Es ist die zentrale Anlaufstelle der Berufs-, Studien- und Laufbahnberatung.","en":"The career information centre (BIZ) provides information and materials on apprenticeships, occupations and the world of work for anyone interested. It is the central point of contact for career, study and vocational guidance.","src":[{"label":"Berufsberatung – Wikipedia","url":"https://de.wikipedia.org/wiki/Berufsberatung"}]},
  178: {"de":"Wichtigster Handelspartner der Schweiz ist die Europäische Union; ein Grossteil der Schweizer Ein- und Ausfuhren entfällt auf EU-Staaten, allen voran die Nachbarländer Deutschland, Italien und Frankreich. Einzelne Länder wie die USA oder China folgen erst danach.","en":"Switzerland's most important trading partner is the European Union; the bulk of Swiss imports and exports involve EU states, above all the neighbouring countries Germany, Italy and France. Individual countries such as the USA or China come only after that.","src":[{"label":"Wirtschaft der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Wirtschaft_der_Schweiz"}]},
  179: {"de":"Arbeitnehmende haben Anspruch auf bezahlte freie Stunden, wenn sie ein öffentliches Amt ausüben, da dies im öffentlichen Interesse liegt und gesetzlich geschützt ist. Private Erledigungen wie Bank- oder Postgänge gehören dagegen nicht dazu.","en":"Employees are entitled to paid time off to carry out a public office, since this serves the public interest and is protected by law. Private errands such as trips to the bank or post office, by contrast, do not qualify.","src":[{"label":"Obligationenrecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Obligationenrecht_(Schweiz)"}]},
  180: {"de":"MWST steht für die Mehrwertsteuer, eine allgemeine Verbrauchssteuer auf Waren und Dienstleistungen, die letztlich von den Konsumentinnen und Konsumenten getragen wird. Der Normalsatz beträgt in der Schweiz 8,1 Prozent.","en":"MWST stands for value-added tax (Mehrwertsteuer), a general consumption tax on goods and services that is ultimately borne by consumers. In Switzerland the standard rate is 8.1 percent.","src":[{"label":"Mehrwertsteuer (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Mehrwertsteuer_(Schweiz)"}]},
  181: {"de":"Jede erwerbstätige Frau, die ein Kind zur Welt bringt, hat Anspruch auf Mutterschaftsurlaub mit Mutterschaftsentschädigung. Der bezahlte Urlaub dauert 14 Wochen (nicht 20), ist nicht auf bestimmte Altersgruppen beschränkt und muss nicht zuerst mit normalen Ferien aufgebraucht werden.","en":"Every employed woman who gives birth is entitled to maternity leave with maternity benefit. The paid leave lasts 14 weeks (not 20), is not limited to certain age groups, and does not have to be used up first by taking regular holidays.","src":[{"label":"Mutterschaftsurlaub – Wikipedia","url":"https://de.wikipedia.org/wiki/Mutterschaftsurlaub"}]},
  182: {"de":"In der Schweiz ist die Mehrehe (Bigamie/Polygamie) verboten: Man darf nicht gleichzeitig mit zwei Personen verheiratet sein. Unverheiratetes Zusammenleben, das Wohnen erwachsener Kinder bei den Eltern oder die alleinige Kinderbetreuung durch den Vater sind dagegen erlaubt.","en":"In Switzerland multiple marriage (bigamy/polygamy) is prohibited: you may not be married to two people at the same time. Living together unmarried, adult children living with their parents, or a father caring for his children alone are all permitted.","src":[{"label":"Bigamie – Wikipedia","url":"https://de.wikipedia.org/wiki/Bigamie"}]},
  183: {"de":"Der Mietvertrag regelt die Rechte und Pflichten der Vertragsparteien, also von Vermieterin und Mieter, etwa Mietzins, Nebenkosten, Kündigung und Nutzung. Er schreibt nicht vor, wie die Wohnung eingerichtet wird oder was gekocht werden darf.","en":"The rental contract sets out the rights and obligations of the contracting parties, i.e. the landlord and the tenant, such as rent, ancillary costs, termination and use. It does not prescribe how the flat is furnished or what may be cooked.","src":[{"label":"Mietvertrag (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Mietvertrag_(Schweiz)"}]},
  184: {"de":"In der Schweiz darf heiraten, wer 18 Jahre alt und urteilsfähig ist. Eine Schwangerschaft, ein Mindesteinkommen oder die Zustimmung der Eltern sind keine Voraussetzungen.","en":"In Switzerland you may marry if you are 18 years old and capable of judgement. Pregnancy, a minimum income or parental consent are not requirements.","src":[{"label":"Eherecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Eherecht_(Schweiz)"}]},
  185: {"de":"Ein Scheidungsbegehren kann von der Ehefrau, vom Ehemann oder von beiden gemeinsam gestellt werden. Kinder oder nur ein bestimmter Ehegatte allein sind nicht ausschliesslich antragsberechtigt.","en":"A divorce petition can be filed by the wife, the husband, or both together. Children, or only one specified spouse alone, are not the sole parties entitled to file.","src":[{"label":"Ehescheidung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Ehescheidung_(Schweiz)"}]},
  186: {"de":"Den Heiratswillen müssen die Verlobten gemeinsam beim Zivilstandsamt anmelden, da beide ihre Eheabsicht persönlich bestätigen müssen. Weder ein Partner allein noch die Eltern können dies stellvertretend tun.","en":"The intention to marry must be registered jointly by the engaged couple at the civil registry office, since both must personally confirm their intent. Neither one partner alone nor the parents can do this on their behalf.","src":[{"label":"Eherecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Eherecht_(Schweiz)"}]},
  187: {"de":"Auf begründetes Verlangen muss man die Vermieterin oder den Vermieter in die Wohnung lassen, etwa für nötige Kontrollen, Unterhalt oder Reparaturen (Art. 257h Obligationenrecht). Andere Personen wie Post, Arbeitgeber oder Wahlkandidierende haben kein solches Zutrittsrecht.","en":"On justified request you must let the landlord into the flat, for example for necessary inspections, maintenance or repairs (Art. 257h of the Code of Obligations). Other people such as the postal service, employers or election candidates have no such right of entry.","src":[{"label":"Mietvertrag (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Mietvertrag_(Schweiz)"}]},
  188: {"de":"Der Mieterinnen- und Mieterverband ist eine private Interessenvertretung der Mietenden, die Beratung und Unterstützung in Mietfragen bietet. Er ist keine staatliche Schlichtungsstelle und keine Wohnungsvermittlung, und nicht alle Mietenden sind automatisch Mitglieder.","en":"The Tenants' Association is a private body representing tenants' interests, offering advice and support in rental matters. It is not a government conciliation authority or a flat-letting agency, and not all tenants are automatically members.","src":[{"label":"Mieterinnen- und Mieterverband Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Mieterinnen-_und_Mieterverband_Schweiz"}]},
  189: {"de":"Eine Voraussetzung für die Eheschliessung ist, dass die Partner nicht eng miteinander verwandt sind (Ehehindernis der Verwandtschaft). Beide müssen zudem volljährig (18) sein, ein gemeinsamer Wohnsitz oder eine bestehende eingetragene Partnerschaft sind nicht verlangt.","en":"One requirement for marriage is that the partners are not closely related to each other (kinship impediment). Both must also be of age (18); a shared residence or an existing registered partnership are not required.","src":[{"label":"Eherecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Eherecht_(Schweiz)"}]},
  190: {"de":"Der Fahrausweis kann namentlich beim Fahren unter Einfluss von Alkohol oder Drogen entzogen werden, da dies die Verkehrssicherheit erheblich gefährdet. Leichtere Verstösse wie Falschparkieren oder unerlaubtes Hupen führen in der Regel nur zu einer Busse.","en":"The driving licence can be withdrawn notably for driving under the influence of alcohol or drugs, as this seriously endangers road safety. Minor offences such as illegal parking or honking usually only result in a fine.","src":[{"label":"Führerausweis und Fahrberechtigung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/F%C3%BChrerausweis_und_Fahrberechtigung_(Schweiz)"}]},
  191: {"de":"Behalten verheiratete Eltern bei der Heirat keinen gemeinsamen Familiennamen, müssen sie bei der Heirat festlegen, welchen ihrer beiden Ledignamen die Kinder tragen sollen. Es gibt also keinen automatischen Vater- oder Mutternamen.","en":"If married parents do not adopt a common family name at marriage, they must decide at the time of marriage which of their two surnames their children will bear. There is thus no automatic father's or mother's name.","src":[{"label":"Eherecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Eherecht_(Schweiz)"}]},
  192: {"de":"Hundebesitzer müssen für ihren Hund eine Hundesteuer (Hundeabgabe) zahlen, die in der Schweiz von den Gemeinden bzw. Kantonen erhoben wird. Eine Geburtsurkunde oder Krankenversicherung ist für den Hund nicht vorgeschrieben.","en":"Dog owners must pay a dog tax for their dog, which in Switzerland is levied by the municipalities or cantons. A birth certificate or health insurance is not required for the dog.","src":[{"label":"Hundesteuer – Wikipedia","url":"https://de.wikipedia.org/wiki/Hundesteuer"}]},
  193: {"de":"Ergänzungsleistungen kann beziehen, wer trotz AHV- oder IV-Rente das Existenzminimum nicht erreicht; sie decken die Lücke zwischen Rente und anerkanntem Bedarf. Sie sind keine Sozialhilfe und nicht für Arbeitslose oder bei tiefem Lohn gedacht.","en":"Supplementary benefits (Ergänzungsleistungen) can be claimed by those who, despite an AHV or IV pension, do not reach the subsistence minimum; they cover the gap between pension and recognised needs. They are not welfare and are not meant for the unemployed or for low wages.","src":[{"label":"Sozialversicherungen (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Sozialversicherungen_(Schweiz)"}]},
  194: {"de":"In der Schweiz besteht ein Krankenversicherungsobligatorium: Jede in der Schweiz wohnhafte Person muss bei einer Krankenkasse für die Grundversicherung versichert sein. Mitgliedschaft in Partei, Sport- oder Automobilclub ist dagegen freiwillig.","en":"Switzerland has compulsory health insurance: every person resident in Switzerland must be insured with a health insurer for basic coverage. Membership in a party, sports or automobile club, by contrast, is voluntary.","src":[{"label":"Krankenversicherung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Krankenversicherung_in_der_Schweiz"}]},
  195: {"de":"Nach Schweizer Vereinsrecht (Art. 60 ff. ZGB) darf grundsätzlich jede Person einen Verein gründen; es braucht weder ein Mindestalter von 21 Jahren noch ein bestimmtes Einkommen oder einen Leistungsausweis. Ein nicht wirtschaftlicher Verein entsteht durch schriftliche Statuten.","en":"Under Swiss association law (Art. 60 ff. of the Civil Code) essentially any person may found an association; neither a minimum age of 21, nor a particular income, nor proof of achievement is required. A non-commercial association comes into being through written statutes.","src":[{"label":"Vereinsrecht (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Vereinsrecht_(Schweiz)"}]},
  196: {"de":"Die Vermögenssteuer auf das Reinvermögen gehört neben der Einkommenssteuer zu den wichtigsten direkten Steuern, die Kantone und Gemeinden erheben. Tabak- und Alkoholsteuern sind Bundessteuern, eine 'Privatsteuer' oder 'Handysteuer' gibt es nicht.","en":"Wealth tax on net assets is, alongside income tax, one of the most important direct taxes levied by cantons and municipalities. Tobacco and alcohol taxes are federal, and there is no such thing as a 'private tax' or 'mobile-phone tax'.","src":[{"label":"Direkte und indirekte Steuer – Wikipedia","url":"https://de.wikipedia.org/wiki/Direkte_und_indirekte_Steuer"}]},
  197: {"de":"Die Einkommenssteuer ist die wichtigste direkte Steuer der Kantone und Gemeinden. Verrechnungssteuer, Alkoholsteuer und Zölle sind dagegen Bundessteuern und fliessen in die Bundeskasse.","en":"Income tax is the most important direct tax of the cantons and municipalities. The withholding tax (Verrechnungssteuer), alcohol tax and customs duties, by contrast, are federal taxes paid to the Confederation.","src":[{"label":"Direkte und indirekte Steuer – Wikipedia","url":"https://de.wikipedia.org/wiki/Direkte_und_indirekte_Steuer"}]},
  198: {"de":"In der Schweiz tragen die Kantone die Verantwortung für die obligatorische Volksschule, während die Gemeinden den Schulbetrieb organisieren. Der Bund hat hier nur eine koordinierende Rolle; eine 'Bundesschulverwaltung' oder einen 'Volksschulrat' gibt es nicht.","en":"In Switzerland the cantons are responsible for compulsory public schooling, while the municipalities organise day-to-day school operations. The Confederation only has a coordinating role; there is no 'federal school administration' or 'public-school council'.","src":[{"label":"Bildungssystem in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Bildungssystem_in_der_Schweiz"}]},
  199: {"de":"Im Kanton Zürich beginnt die obligatorische Schulzeit mit dem Kindergarten, der zwei Jahre dauert und Teil der elfjährigen Volksschule ist. Erst danach folgt die Primarschule.","en":"In the canton of Zurich, compulsory schooling begins with kindergarten, which lasts two years and forms part of the eleven-year compulsory school. Primary school only follows afterwards.","src":[{"label":"Bildungssystem in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Bildungssystem_in_der_Schweiz"}]},
  200: {"de":"Ein Quartierverein vertritt freiwillig die Interessen der Bewohnerinnen und Bewohner eines Quartiers gegenüber den Behörden und fördert das gesellschaftliche Zusammenleben. Die Mitgliedschaft ist freiwillig, nicht automatisch.","en":"A neighbourhood association (Quartierverein) voluntarily represents the interests of a district's residents towards the authorities and fosters community life. Membership is voluntary, not automatic.","src":[{"label":"Verein – Wikipedia","url":"https://de.wikipedia.org/wiki/Verein"}]},
  201: {"de":"Der Finanzausgleich verteilt finanzielle Mittel um, damit finanzschwache Gemeinden ihre öffentlichen Aufgaben trotzdem erfüllen können. Er zwingt arme Gemeinden nicht, sondern unterstützt sie.","en":"Financial equalisation redistributes funds so that financially weaker municipalities can still carry out their public tasks. It does not coerce poor municipalities but supports them.","src":[{"label":"Finanzausgleich – Wikipedia","url":"https://de.wikipedia.org/wiki/Finanzausgleich"}]},
  202: {"de":"Reicht das Einkommen nicht für den Lebensunterhalt, gewährt die Wohngemeinde Sozialhilfe als finanzielle Unterstützung. Begriffe wie 'Kostgeld', 'Gemeinderappen' oder 'Kantonsgeld' existieren in diesem Zusammenhang nicht.","en":"If income is not enough to cover living costs, the municipality of residence provides social assistance (Sozialhilfe) as financial support. Terms like 'meal money', 'municipal cent' or 'cantonal money' do not exist in this context.","src":[{"label":"Sozialhilfe (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Sozialhilfe_(Schweiz)"}]},
  203: {"de":"Über Angebote und Regelungen der Gemeinde informiert man sich in der Regel in der Lokalzeitung oder im Internet (auf der Website der Gemeinde). Diese Kanäle sind aktuell und umfassend, während Fernsehen, Anschlagbretter oder Plakate nur Einzelinformationen liefern.","en":"You normally find out about a municipality's services and rules in the local newspaper or on the internet (the municipality's website). These channels are up to date and comprehensive, whereas television, notice boards or posters only carry isolated pieces of information.","src":[{"label":"Politische Gemeinde (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Politische_Gemeinde_(Schweiz)"}]},
  204: {"de":"Die Gemeinden kommen für die Sozialhilfe auf, die Menschen in einer Notlage unterstützt. Die Altersrente (AHV) ist Sache des Bundes; Kosten für die Fahrprüfung oder private Reisen sind keine Sozialleistungen.","en":"Municipalities pay for social assistance, which supports people in an emergency situation. The old-age pension (AHV) is a federal matter, and driving-test fees or leisure travel costs are not social benefits.","src":[{"label":"Sozialhilfe (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Sozialhilfe_(Schweiz)"}]},
  205: {"de":"Für die Primarschule sind der Kanton und die Gemeinden gemeinsam zuständig: Der Kanton setzt die rechtlichen Rahmenbedingungen, die Gemeinden finanzieren und organisieren den Schulbetrieb. Eltern oder Bund tragen diese Verantwortung nicht.","en":"Primary school is the joint responsibility of the canton and the municipalities: the canton sets the legal framework while the municipalities finance and organise school operations. Parents and the Confederation do not bear this responsibility.","src":[{"label":"Bildungssystem in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Bildungssystem_in_der_Schweiz"}]},
  206: {"de":"Wer heiraten möchte, muss sich beim Zivilstandsamt melden, das die Ehe vorbereitet und beurkundet. Eltern, eine Partnervermittlung oder eine Eheberatung haben damit keine amtliche Funktion.","en":"Anyone wishing to marry must register with the civil registry office (Zivilstandsamt), which prepares and records the marriage. Parents, a dating agency or marriage counselling have no official role in this.","src":[{"label":"Zivilstandsamt – Wikipedia","url":"https://de.wikipedia.org/wiki/Zivilstandsamt"}]},
  207: {"de":"Bei einem Umzug muss man sich bei der Gemeinde, konkret bei der Einwohnerkontrolle, an- bzw. abmelden. Steuerbehörden, Polizei oder Gebäudeversicherung sind dafür nicht zuständig.","en":"When moving, you must register (or deregister) with the municipality, specifically the residents' registration office (Einwohnerkontrolle). The tax authorities, police or building insurer are not responsible for this.","src":[{"label":"Einwohnerkontrolle – Wikipedia","url":"https://de.wikipedia.org/wiki/Einwohnerkontrolle"}]},
  208: {"de":"In den Zürcher Gemeinden leitet die Schulleitung die Volksschule operativ und pädagogisch; sie führt das Lehrpersonal und ist für den Schulbetrieb verantwortlich. Elternrat, Schulsekretariat und Lehrerkonferenz haben unterstützende oder beratende, aber keine leitende Funktion.","en":"In the municipalities of Zürich, the school management (Schulleitung) runs the public school operationally and pedagogically, leading the teaching staff and being responsible for daily operations. The parents' council, the secretariat and the teachers' conference play supporting or advisory roles but do not lead the school.","src":[{"label":"Volksschule – Wikipedia","url":"https://de.wikipedia.org/wiki/Volksschule"}]},
  209: {"de":"1798 marschierten französische Truppen in die Schweiz ein, und unter Napoleon Bonaparte wurde die lose Alte Eidgenossenschaft kurzzeitig in die zentralistische Helvetische Republik umgewandelt. Habsburg, Friedrich der Grosse und Karl der Kühne gehören in andere Epochen.","en":"In 1798 French troops invaded Switzerland, and under Napoleon Bonaparte the loose Old Confederacy was briefly turned into the centralized Helvetic Republic. Habsburg, Frederick the Great and Charles the Bold belong to other eras.","src":[{"label":"Helvetische Republik – Wikipedia","url":"https://de.wikipedia.org/wiki/Helvetische_Republik"}]},
  210: {"de":"Alfred Escher war eine der einflussreichsten Persönlichkeiten der Schweiz im 19. Jahrhundert und massgeblich an der Gründung des Eidgenössischen Polytechnikums (heutige ETH), am Eisenbahnbau (Nordostbahn, Gotthardbahn) und an der Gründung der Schweizerischen Kreditanstalt (heute Credit Suisse) beteiligt.","en":"Alfred Escher was one of the most influential figures in 19th-century Switzerland, instrumental in founding the Federal Polytechnic (today's ETH), building the railways (Nordostbahn, Gotthard line) and founding the Schweizerische Kreditanstalt (today Credit Suisse).","src":[{"label":"Alfred Escher – Wikipedia","url":"https://de.wikipedia.org/wiki/Alfred_Escher"}]},
  211: {"de":"Eine zentrale Forderung des Landesstreiks von 1918 war die Verkürzung der Arbeitszeit; die 48-Stunden-Woche wurde in der Folge 1919/20 weitgehend eingeführt. Verstaatlichung der Fabriken, sechs Wochen Ferien oder Gratisfahrten gehörten nicht zu den erreichten Ergebnissen.","en":"A key demand of the 1918 general strike was a reduction of working hours, and the 48-hour week was duly introduced in 1919/20. Nationalizing factories, six weeks of holidays or free transport were not among the outcomes.","src":[{"label":"Landesstreik – Wikipedia","url":"https://de.wikipedia.org/wiki/Landesstreik"}]},
  212: {"de":"Die «Schwarzenbach-Initiative» von 1970 (zweite Überfremdungsinitiative) verlangte eine Begrenzung des Ausländeranteils, konkret auf höchstens 10 Prozent pro Kanton. Sie wurde an der Volksabstimmung knapp abgelehnt.","en":"The 1970 \"Schwarzenbach Initiative\" (the second \"over-foreignization\" initiative) called for limiting the number of foreigners, specifically to at most 10 percent per canton. It was narrowly rejected in the popular vote.","src":[{"label":"Schwarzenbach-Initiative – Wikipedia","url":"https://de.wikipedia.org/wiki/Schwarzenbach-Initiative"}]},
  213: {"de":"1848 wurde mit der ersten Bundesverfassung aus dem losen Staatenbund der moderne Schweizer Bundesstaat geschaffen. Die Neutralitätsgarantie (1815) und Marignano (1515) fallen in andere Jahre, eine formelle Unabhängigkeit vom Reich datiert auf 1648.","en":"In 1848 the first Federal Constitution transformed the loose confederation of states into the modern Swiss federal state. The guarantee of neutrality (1815) and Marignano (1515) fall in other years, and formal independence from the Empire dates to 1648.","src":[{"label":"Schweizerischer Bundesstaat – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerischer_Bundesstaat"}]},
  214: {"de":"Die Schweizer Nationalhymne heisst Schweizerpsalm; sie wurde 1841 komponiert und 1981 offiziell als Nationalhymne bestätigt. Die anderen Bezeichnungen sind frei erfunden.","en":"The Swiss national anthem is called the Swiss Psalm (Schweizerpsalm); it was composed in 1841 and officially confirmed as the national anthem in 1981. The other names are invented.","src":[{"label":"Schweizerpsalm – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerpsalm"}]},
  215: {"de":"Der Kanton Jura entstand 1979 durch Abspaltung vom Kanton Bern und ist damit der jüngste Schweizer Kanton. St. Gallen, Zürich und Solothurn bestehen seit deutlich früher.","en":"The Canton of Jura was created in 1979 by separating from the Canton of Bern, making it Switzerland's youngest canton. St. Gallen, Zürich and Solothurn have existed for much longer.","src":[{"label":"Kanton Jura – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Jura"}]},
  216: {"de":"Im 16. Jahrhundert spaltete die Reformation (u. a. mit Zwingli in Zürich und Calvin in Genf) die westliche Christenheit und prägte die Schweiz konfessionell stark. Die übrigen Begriffe bezeichnen keine solche Bewegung jener Zeit.","en":"In the 16th century the Reformation (led in Switzerland by figures such as Zwingli in Zürich and Calvin in Geneva) split Western Christianity and deeply shaped Switzerland's confessional landscape. The other terms do not describe such a movement of that era.","src":[{"label":"Reformation – Wikipedia","url":"https://de.wikipedia.org/wiki/Reformation"}]},
  217: {"de":"Auf Bundesebene erhielten die Schweizer Frauen das Stimm- und Wahlrecht erst 1971 durch eine Volksabstimmung. Damit war die Schweiz eines der letzten Länder Europas mit dem Frauenstimmrecht.","en":"At the federal level, Swiss women only gained the right to vote and stand for election in 1971, following a popular vote. This made Switzerland one of the last countries in Europe to introduce women's suffrage.","src":[{"label":"Frauenstimmrecht in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Frauenstimmrecht_in_der_Schweiz"}]},
  218: {"de":"In den 1950er-Jahren kamen die meisten ausländischen Arbeitskräfte für den wirtschaftlichen Aufschwung aus Italien; sie prägten als grösste Einwanderergruppe diese Phase der Arbeitsmigration. Portugiesische, griechische und französische Zuwanderung war damals deutlich geringer oder kam erst später.","en":"In the 1950s most of the foreign workers driving the economic boom came from Italy; as the largest immigrant group they shaped this phase of labor migration. Portuguese, Greek and French immigration was much smaller at the time or came later.","src":[{"label":"Italiener in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Italiener_in_der_Schweiz"}]},
  219: {"de":"In den 1990er-Jahren flohen viele Menschen aus (Ex-)Jugoslawien vor den Jugoslawienkriegen in die Schweiz und suchten dort Schutz. Studium, Verwandtenbesuche oder Bauprojekte waren nicht der Hauptgrund dieser Zuwanderung.","en":"In the 1990s many people from (former) Yugoslavia fled to Switzerland to escape the Yugoslav wars and sought protection there. Studying, visiting relatives or construction projects were not the main reason for this migration.","src":[{"label":"Jugoslawienkriege – Wikipedia","url":"https://de.wikipedia.org/wiki/Jugoslawienkriege"}]},
  220: {"de":"Die Schweiz war im Zweiten Weltkrieg neutral, unterhielt aber dennoch politische und vor allem wirtschaftliche Beziehungen (Handel, Bankgeschäfte, Waffenlieferungen) sowohl zu den Achsenmächten als auch zu den Alliierten. Sie war also weder Bündnispartner einer Seite noch völlig beziehungslos.","en":"During the Second World War Switzerland was neutral, yet it still maintained political and especially economic ties (trade, banking, arms supplies) with both the Axis and the Allies. It was therefore neither an ally of either side nor entirely without relations.","src":[{"label":"Schweiz im Zweiten Weltkrieg – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz_im_Zweiten_Weltkrieg"}]},
  221: {"de":"Die Industrialisierung der Schweiz begann im frühen 19. Jahrhundert vor allem mit der Textilindustrie (besonders Baumwollverarbeitung in der Ostschweiz und im Zürcher Oberland). Stahl- und Autoindustrie spielten damals keine Rolle, und Kohle musste die rohstoffarme Schweiz importieren.","en":"Switzerland's industrialisation began in the early 19th century primarily with the textile industry (especially cotton processing in eastern Switzerland and the Zurich Oberland). Steel and car industries played no role yet, and resource-poor Switzerland had to import coal.","src":[{"label":"Industrialisierung der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Industrialisierung_der_Schweiz"}]},
  222: {"de":"Der Grundsatz der Gleichberechtigung von Mann und Frau wurde 1981 durch eine Volksabstimmung in der Bundesverfassung verankert. Das Frauenstimmrecht auf Bundesebene war zuvor 1971 eingeführt worden.","en":"The principle of equality between men and women was enshrined in the Federal Constitution in 1981 by popular vote. Women's suffrage at the federal level had been introduced earlier, in 1971.","src":[{"label":"Gleichstellung der Geschlechter – Wikipedia","url":"https://de.wikipedia.org/wiki/Gleichstellung_der_Geschlechter"}]},
  223: {"de":"Im 19. Jahrhundert wandelte sich die Schweiz vom Agrarstaat zum Industriestaat: Die Landwirtschaft verlor an Bedeutung, während Fabriken (zuerst die Textilindustrie) und später Maschinen- und Chemieindustrie wuchsen. Eine Gross- oder Kolonialmacht wurde die Schweiz nie.","en":"In the 19th century Switzerland transformed from an agrarian into an industrial state: agriculture lost importance while factories (first textiles, later machinery and chemicals) grew. Switzerland never became a great power or a colonial power.","src":[{"label":"Industrialisierung der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Industrialisierung_der_Schweiz"}]},
  224: {"de":"In den 1960er-Jahren erlebte die Schweiz während des Nachkriegsbooms ('Wirtschaftswunder') starkes Wirtschaftswachstum und Vollbeschäftigung, wodurch der Lebensstandard für breite Bevölkerungsschichten deutlich anstieg. In den 1930er-Jahren herrschte dagegen Wirtschaftskrise.","en":"In the 1960s, during the post-war boom, Switzerland experienced strong economic growth and full employment, which markedly raised living standards for large parts of the population. The 1930s, by contrast, were marked by economic crisis.","src":[{"label":"Geschichte der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Geschichte_der_Schweiz"}]},
  225: {"de":"Die Schweiz besass selbst keine Kolonien, profitierte aber vom europäischen Kolonialsystem: Durch den Zugang zu billigen Rohstoffen (etwa Baumwolle) und neuen Absatzmärkten konnte sie sich als Industrienation etablieren. Schweizer waren zudem als Händler, Plantagenbesitzer und Söldner am Kolonialhandel beteiligt.","en":"Switzerland itself held no colonies but benefited from the European colonial system: access to cheap raw materials (such as cotton) and new markets allowed it to establish itself as an industrial nation. Swiss people also took part in the colonial economy as traders, plantation owners and mercenaries.","src":[{"label":"Schweizerische Kolonialbeziehungen – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerische_Kolonialbeziehungen"}]},
  226: {"de":"Der Sage und dem Bundesbrief nach schlossen sich 1291 die drei Urkantone Uri, Schwyz und Unterwalden zu einem Bündnis zusammen, das als Ursprung der Eidgenossenschaft gilt. Bern, Zürich und Zug traten erst später bei.","en":"According to tradition and the Federal Charter, in 1291 the three original cantons Uri, Schwyz and Unterwalden formed an alliance regarded as the origin of the Swiss Confederation. Bern, Zurich and Zug joined only later.","src":[{"label":"Bundesbrief – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesbrief"}]},
  227: {"de":"Zur Zeit des alten Roms lebten im Gebiet der heutigen Schweiz vor allem die Helvetier, ein keltischer Volksstamm. Die 'Eidgenossen' entstanden erst ab 1291, während Etrusker und Illyrier in anderen Regionen Europas siedelten.","en":"In Roman times the area of present-day Switzerland was inhabited mainly by the Helvetii, a Celtic tribe. The 'Eidgenossen' (Confederates) only emerged from 1291 onward, while the Etruscans and Illyrians lived in other parts of Europe.","src":[{"label":"Helvetier – Wikipedia","url":"https://de.wikipedia.org/wiki/Helvetier"}]},
  228: {"de":"Im Sonderbundskrieg von 1847 standen sich die katholisch-konservativen Kantone (die den 'Sonderbund' gebildet hatten) und die liberal-radikalen, mehrheitlich protestantischen Kantone gegenüber. Die Liberalen wollten einen Bundesstaat, die Konservativen verteidigten die kantonale Eigenständigkeit.","en":"In the Sonderbund War of 1847, the Catholic-conservative cantons (which had formed the 'Sonderbund') faced the liberal-radical, mostly Protestant cantons. The liberals wanted a federal state, while the conservatives defended cantonal autonomy.","src":[{"label":"Sonderbundskrieg – Wikipedia","url":"https://de.wikipedia.org/wiki/Sonderbundskrieg"}]},
  229: {"de":"Das Amphitheater in Avenches stammt von den Römern: Avenches war als Aventicum die Hauptstadt der Helvetier (Civitas Helvetiorum) und ein bedeutendes römisches Zentrum, von dem heute noch das Amphitheater und weitere Bauten zeugen.","en":"The amphitheatre in Avenches dates from the Romans: as Aventicum, Avenches was the capital of the Helvetii (Civitas Helvetiorum) and an important Roman centre, of which the amphitheatre and other structures still bear witness today.","src":[{"label":"Aventicum – Wikipedia","url":"https://de.wikipedia.org/wiki/Aventicum"}]},
  230: {"de":"Nach der Niederlage bei Marignano 1515 verzichteten die Eidgenossen auf weitere Eroberungen und eine eigenständige Grossmachtpolitik; 1516 schlossen sie mit Frankreich den 'Ewigen Frieden'. Dies gilt als ein wichtiger Schritt zur späteren schweizerischen Neutralität.","en":"After the defeat at Marignano in 1515, the Confederates gave up further conquests and any independent great-power ambitions; in 1516 they concluded the 'Perpetual Peace' with France. This is seen as an important step toward later Swiss neutrality.","src":[{"label":"Schlacht bei Marignano – Wikipedia","url":"https://de.wikipedia.org/wiki/Schlacht_bei_Marignano"}]},
  231: {"de":"Mit der Reformation im 16. Jahrhundert (in der Schweiz u. a. durch Huldrych Zwingli und Johannes Calvin) entstand der protestantische Glaube als neue christliche Glaubensrichtung. Judentum, Buddhismus und Islam sind dagegen viel ältere, unabhängig entstandene Religionen.","en":"The Reformation of the 16th century (in Switzerland led notably by Huldrych Zwingli and John Calvin) gave rise to Protestantism as a new Christian denomination. Judaism, Buddhism and Islam, by contrast, are much older religions that arose independently.","src":[{"label":"Reformation – Wikipedia","url":"https://de.wikipedia.org/wiki/Reformation"}]},
  232: {"de":"Die Reformation im 16. Jahrhundert (in Zürich durch Huldrych Zwingli) spaltete die Eidgenossenschaft in reformierte und katholisch gebliebene Orte und führte zu konfessionellen Konflikten. Die Täuferbewegung war nur eine Randströmung der Reformation, der Generalstreik (1918) und die Klosteraufhebung gehören in andere Zusammenhänge.","en":"The Reformation in the 16th century (led in Zurich by Huldrych Zwingli) split the Confederation into reformed and Catholic territories and triggered religious conflicts. The Anabaptist movement was only a fringe of the Reformation, while the general strike (1918) and dissolution of monasteries belong to other contexts.","src":[{"label":"Reformation in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Reformation_in_der_Schweiz"}]},
  233: {"de":"1798 marschierten französische Truppen in die Schweiz ein und beendeten die Alte Eidgenossenschaft; an ihre Stelle trat die zentralistische Helvetische Republik. Dies brachte die grundlegende politische Neuordnung.","en":"In 1798 French troops invaded Switzerland and ended the Old Confederacy, replacing it with the centralised Helvetic Republic. This brought about the fundamental political reorganisation.","src":[{"label":"Helvetische Republik – Wikipedia","url":"https://de.wikipedia.org/wiki/Helvetische_Republik"}]},
  234: {"de":"Am Wiener Kongress 1815 anerkannten die europäischen Grossmächte die immerwährende Neutralität der Schweiz und garantierten deren Unverletzlichkeit. Die anderen Punkte wurden dort nicht festgelegt.","en":"At the Congress of Vienna in 1815 the European great powers recognised Switzerland's perpetual neutrality and guaranteed its inviolability. The other options were not decided there.","src":[{"label":"Schweizer Neutralität – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_Neutralit%C3%A4t"}]},
  235: {"de":"Mit der Bundesverfassung von 1848 wurde aus dem lockeren Staatenbund ein föderalistischer Bundesstaat, in dem Aufgaben zwischen Bund und Kantonen aufgeteilt sind. Es war weder ein reiner Zentralstaat noch eine Monarchie oder Volksrepublik.","en":"With the Federal Constitution of 1848, the loose confederation of states became a federalist federal state in which tasks are divided between the federal government and the cantons. It was neither a purely centralised state nor a monarchy or people's republic.","src":[{"label":"Bundesverfassung (Schweiz) – Wikipedia","url":"https://de.wikipedia.org/wiki/Bundesverfassung_(Schweiz)"}]},
  236: {"de":"1863 gründete Henry Dunant in Genf das Internationale Komitee vom Roten Kreuz (IKRK), die bis heute bedeutendste humanitäre Organisation mit Sitz in der Schweiz. Amnesty International, Pro Juventute und die Glückskette entstanden viel später.","en":"In 1863 Henry Dunant founded the International Committee of the Red Cross (ICRC) in Geneva, still the most important humanitarian organisation based in Switzerland. Amnesty International, Pro Juventute and the Glückskette were founded much later.","src":[{"label":"Internationales Komitee vom Roten Kreuz – Wikipedia","url":"https://de.wikipedia.org/wiki/Internationales_Komitee_vom_Roten_Kreuz"}]},
  237: {"de":"Die Dampfmaschine war die zentrale Erfindung der industriellen Revolution und veränderte ab dem 18. Jahrhundert die Schweizer Produktion (u. a. die Textilindustrie) grundlegend. Benzin- und Elektromotor sowie der Computer kamen erst deutlich später.","en":"The steam engine was the key invention of the industrial revolution and from the 18th century fundamentally transformed Swiss production (notably the textile industry). The petrol and electric motors and the computer came much later.","src":[{"label":"Dampfmaschine – Wikipedia","url":"https://de.wikipedia.org/wiki/Dampfmaschine"}]},
  238: {"de":"Das Eidgenössische Fabrikgesetz von 1877 verbot die Kinderarbeit, weil Kinder in den Fabriken arbeiten mussten und deshalb nicht die Schule besuchen konnten. Es ging vor allem um den Schutz der Gesundheit und der Schulbildung der Kinder.","en":"The Federal Factory Act of 1877 banned child labour because children had to work in factories and therefore could not attend school. The aim was above all to protect children's health and education.","src":[{"label":"Fabrikgesetz – Wikipedia","url":"https://de.wikipedia.org/wiki/Fabrikgesetz"}]},
  239: {"de":"1948 trat die Alters- und Hinterlassenenversicherung (AHV) in Kraft, die wichtigste Säule der staatlichen Altersvorsorge der Schweiz. Sie sichert das Einkommen im Alter und für Hinterbliebene.","en":"In 1948 the Old-Age and Survivors' Insurance (AHV) came into force, the most important pillar of Switzerland's state pension system. It secures income in old age and for surviving dependants.","src":[{"label":"Alters- und Hinterlassenenversicherung – Wikipedia","url":"https://de.wikipedia.org/wiki/Alters-_und_Hinterlassenenversicherung"}]},
  240: {"de":"Erst die Abstimmung vom 7. Februar 1971 führte das Frauenstimmrecht auf Bundesebene ein; seither dürfen Schweizerinnen national wählen und abstimmen. 1919 und 1946 scheiterten entsprechende Bestrebungen noch.","en":"Only the referendum of 7 February 1971 introduced women's suffrage at the federal level; since then Swiss women may vote and take part in national ballots. Earlier efforts in 1919 and 1946 had failed.","src":[{"label":"Frauenstimmrecht in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Frauenstimmrecht_in_der_Schweiz"}]},
  241: {"de":"Elisabeth Kopp (FDP) wurde 1984 als erste Frau in den Bundesrat gewählt. Ruth Dreifuss, Ruth Metzler und Micheline Calmy-Rey folgten erst später.","en":"Elisabeth Kopp (FDP) was elected in 1984 as the first woman to join the Federal Council. Ruth Dreifuss, Ruth Metzler and Micheline Calmy-Rey followed only later.","src":[{"label":"Elisabeth Kopp – Wikipedia","url":"https://de.wikipedia.org/wiki/Elisabeth_Kopp"}]},
  242: {"de":"Mit der Annahme der Bilateralen Verträge I im Jahr 2000 wurde die Grundlage der heutigen geregelten Beziehungen der Schweiz zur EU gelegt. Sie ersetzten den 1992 abgelehnten EWR-Beitritt durch einen sektoriellen, bilateralen Weg.","en":"The approval of the Bilateral Agreements I in 2000 laid the foundation for Switzerland's present, regulated relationship with the EU. They replaced the EEA membership rejected in 1992 with a sectoral, bilateral approach.","src":[{"label":"Bilaterale Verträge Schweiz–EU – Wikipedia","url":"https://de.wikipedia.org/wiki/Bilaterale_Vertr%C3%A4ge_zwischen_der_Schweiz_und_der_Europ%C3%A4ischen_Union"}]},
  243: {"de":"Wilhelm Tell ist eine Innerschweizer Sagenfigur, die als Symbol des Widerstands gegen fremde (habsburgische) Herrscher gilt. Historisch belegt ist er nicht; bekannt wurde er u. a. durch Schillers Drama.","en":"Wilhelm Tell is a legendary figure from central Switzerland, regarded as a symbol of resistance against foreign (Habsburg) rulers. He is not historically documented and became famous through, among others, Schiller's play.","src":[{"label":"Wilhelm Tell – Wikipedia","url":"https://de.wikipedia.org/wiki/Wilhelm_Tell"}]},
  244: {"de":"Henry Dunant gründete 1863 in Genf das Internationale Komitee vom Roten Kreuz (IKRK), nachdem er die Folgen der Schlacht von Solferino miterlebt hatte. Der Christliche Verein junger Männer (CVJM), die Pro Juventute und der Weltpostverein wurden von anderen gegründet.","en":"Henry Dunant founded the International Committee of the Red Cross (ICRC) in Geneva in 1863, after witnessing the suffering at the Battle of Solferino. The YMCA, Pro Juventute and the Universal Postal Union were founded by others.","src":[{"label":"Henry Dunant – Wikipedia","url":"https://de.wikipedia.org/wiki/Henry_Dunant"}]},
  245: {"de":"Die Schweiz ist seit Jahrhunderten weltweit führend in der Uhrenindustrie; Marken aus Genf und dem Jura geniessen für Präzision und Qualität internationalen Ruf. Die anderen Branchen waren nie weltweit prägend für die Schweiz.","en":"For centuries Switzerland has been a world leader in watchmaking; brands from Geneva and the Jura region are internationally renowned for precision and quality. The other industries were never globally defining for Switzerland.","src":[{"label":"Uhrenindustrie – Wikipedia","url":"https://de.wikipedia.org/wiki/Uhrenindustrie"}]},
  246: {"de":"Im 19. Jahrhundert verliessen viele Schweizerinnen und Schweizer das Land wegen Hunger, Armut und Arbeitslosigkeit, etwa nach Missernten und während wirtschaftlicher Not, und wanderten vor allem nach Nord- und Südamerika aus. Politische Verfolgung war nicht der Hauptgrund.","en":"In the 19th century many Swiss emigrated because of hunger, poverty and unemployment, for example after crop failures and during economic hardship, mostly to North and South America. Political persecution was not the main reason.","src":[{"label":"Auswanderung – Wikipedia","url":"https://de.wikipedia.org/wiki/Auswanderung"}]},
  247: {"de":"Während des Zweiten Weltkriegs wurde der Sechseläutenplatz im Rahmen der «Anbauschlacht» (Plan Wahlen) zur Selbstversorgung landwirtschaftlich genutzt und als Acker- bzw. Kartoffelfeld bebaut. Heute ist es der grösste Platz der Stadt Zürich, vor dem Opernhaus.","en":"During the Second World War the Sechseläutenplatz was farmed under the national food-production campaign (Plan Wahlen) to boost self-sufficiency, used as cropland and a potato field. Today it is the largest square in the city of Zürich, in front of the opera house.","src":[{"label":"Sechseläutenplatz – Wikipedia","url":"https://de.wikipedia.org/wiki/Sechsel%C3%A4utenplatz"}]},
  248: {"de":"Zur Römerzeit hiess die Siedlung an der Stelle des heutigen Zürich Turicum. Vitudurum war Winterthur, Vindonissa lag bei Brugg und Aquae Helveticae war Baden.","en":"In Roman times the settlement on the site of present-day Zurich was called Turicum. Vitudurum was Winterthur, Vindonissa lay near Brugg, and Aquae Helveticae was Baden.","src":[{"label":"Turicum – Wikipedia","url":"https://de.wikipedia.org/wiki/Turicum"}]},
  249: {"de":"Die Römer brachten die Badekultur in die Region Zürich; öffentliche Bäder (Thermen) gehörten zum römischen Alltag. Porzellan, Alphorn und tropische Gewächshäuser sind viel jüngere oder nicht-römische Erscheinungen.","en":"The Romans introduced bathing culture to the Zurich area; public baths (thermae) were a normal part of Roman life. Porcelain, the alphorn and tropical greenhouses are far more recent or non-Roman.","src":[{"label":"Badekultur – Wikipedia","url":"https://de.wikipedia.org/wiki/Badekultur"}]},
  250: {"de":"Zwischen etwa 5000 und 1000 v. Chr. errichteten Menschen am Zürichsee Pfahlbauten, Siedlungen auf Pfählen am Seeufer. Mehrere dieser prähistorischen Fundstellen gehören heute zum UNESCO-Welterbe.","en":"Between roughly 5000 and 1000 BC people on Lake Zurich built pile dwellings, settlements raised on posts along the lakeshore. Several of these prehistoric sites are now part of the UNESCO World Heritage.","src":[{"label":"Pfahlbau – Wikipedia","url":"https://de.wikipedia.org/wiki/Pfahlbau"}]},
  251: {"de":"Zwischen 1611 und 1635 starb fast die Hälfte der Zürcher Bevölkerung an der Pest, die in mehreren schweren Epidemiewellen wütete. Corona, Krebs und die Spanische Grippe gehören in viel spätere Zeiten.","en":"Between 1611 and 1635 nearly half of Zurich's population died of the plague, which struck in several severe epidemic waves. Covid, cancer and the Spanish flu belong to much later eras.","src":[{"label":"Pest – Wikipedia","url":"https://de.wikipedia.org/wiki/Pest"}]},
  252: {"de":"Ulrich Zwingli war der führende Reformator in Zürich und löste ab 1519 die Reformation in der Stadt aus. Er war weder Unternehmer noch Naturwissenschaftler oder Musiker.","en":"Ulrich Zwingli was the leading reformer in Zurich and from 1519 set the Reformation in motion in the city. He was neither a businessman nor a scientist or musician.","src":[{"label":"Huldrych Zwingli – Wikipedia","url":"https://de.wikipedia.org/wiki/Huldrych_Zwingli"}]},
  253: {"de":"Den Kanton Zürich im modernen Sinn gibt es seit 1803, als er mit der Mediationsakte Napoleons als gleichberechtigter Kanton der Schweizerischen Eidgenossenschaft entstand. 1351 trat Zürich dem Bund bei, 1798 begann die Helvetik.","en":"The Canton of Zurich in its modern form has existed since 1803, when Napoleon's Act of Mediation established it as an equal canton of the Swiss Confederation. Zurich joined the Confederation in 1351, and the Helvetic Republic began in 1798.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  254: {"de":"Die Kirche in Zürich wurde von Ulrich Zwingli reformiert, dem Begründer der reformierten Tradition in der Schweiz. Martin Luther wirkte in Deutschland, Jean Calvin in Genf und Jan Hus lebte schon im 15. Jahrhundert in Böhmen.","en":"The church in Zurich was reformed by Ulrich Zwingli, the founder of the Reformed tradition in Switzerland. Martin Luther worked in Germany, John Calvin in Geneva, and Jan Hus lived in Bohemia back in the 15th century.","src":[{"label":"Huldrych Zwingli – Wikipedia","url":"https://de.wikipedia.org/wiki/Huldrych_Zwingli"}]},
  255: {"de":"Emilie Lieberherr setzte sich Ende der 1960er-Jahre als führende Persönlichkeit für das Frauenstimmrecht ein und präsidierte das Aktionskomitee des Marschs nach Bern von 1969. Sie war später die erste Frau im Zürcher Stadtrat.","en":"In the late 1960s Emilie Lieberherr was a leading figure campaigning for women's suffrage and chaired the action committee of the 1969 March on Bern. She later became the first woman on Zurich's city executive.","src":[{"label":"Emilie Lieberherr – Wikipedia","url":"https://de.wikipedia.org/wiki/Emilie_Lieberherr"}]},
  256: {"de":"Philippe Suchard (Marke Suchard/Milka) und Rudolphe Lindt (Erfinder des Conchierverfahrens, Lindt) gründeten beide Schokoladefabriken und prägten die weltberühmte Schweizer Schokoladenindustrie. Mit Textil, Druck oder Maschinen hatten sie nichts zu tun.","en":"Philippe Suchard (the Suchard/Milka brand) and Rudolphe Lindt (inventor of the conching process, Lindt) both founded chocolate factories and shaped Switzerland's world-famous chocolate industry. They had nothing to do with textiles, printing or machinery.","src":[{"label":"Philippe Suchard – Wikipedia","url":"https://de.wikipedia.org/wiki/Philippe_Suchard"}]},
  257: {"de":"Der 2016 eröffnete Gotthard-Basistunnel ist mit rund 57 km der längste Eisenbahntunnel der Welt. Er war weder der erste noch der einzige Tunnel Europas und ist auch nicht für den grössten Durchmesser bekannt.","en":"Opened in 2016, the Gotthard Base Tunnel is, at about 57 km, the longest railway tunnel in the world. It was neither the first nor the only tunnel in Europe, nor is it known for the largest diameter.","src":[{"label":"Gotthard-Basistunnel – Wikipedia","url":"https://de.wikipedia.org/wiki/Gotthard-Basistunnel"}]},
  258: {"de":"Simplon, Gotthard und Grosser Sankt Bernhard sind bekannte Übergänge über die Alpen, also Schweizer Alpenpässe, die Nord und Süd verbinden. Es handelt sich nicht um Käsesorten oder Naturreservate.","en":"Simplon, Gotthard and Great St Bernard are well-known crossings over the Alps, i.e. Swiss Alpine passes connecting north and south. They are not cheeses or nature reserves.","src":[{"label":"Alpenpass – Wikipedia","url":"https://de.wikipedia.org/wiki/Alpenpass"}]},
  259: {"de":"Der Rhein entspringt in den Schweizer Alpen und fliesst über Deutschland und die Niederlande in die Nordsee. Er erreicht weder das Schwarze Meer noch das Mittelmeer oder den Pazifik.","en":"The Rhine rises in the Swiss Alps and flows through Germany and the Netherlands into the North Sea. It reaches neither the Black Sea, the Mediterranean, nor the Pacific.","src":[{"label":"Rhein – Wikipedia","url":"https://de.wikipedia.org/wiki/Rhein"}]},
  260: {"de":"Die Rhone entspringt am Rhonegletscher im Wallis, durchfliesst den Genfersee und mündet in Südfrankreich ins Mittelmeer. Die anderen Meere liegen geografisch nicht im Einzugsgebiet der Rhone.","en":"The Rhone rises at the Rhone Glacier in Valais, flows through Lake Geneva and empties into the Mediterranean in southern France. The other seas are not part of the Rhone's catchment.","src":[{"label":"Rhone – Wikipedia","url":"https://de.wikipedia.org/wiki/Rhone"}]},
  261: {"de":"Rund zwei Drittel der ausländischen Bevölkerung der Schweiz stammen aus einem EU- bzw. EFTA-Land, vor allem aus Italien, Deutschland, Portugal und Frankreich. Italien allein stellt nur einen Teil davon, daher ist die Gesamtaussage EU-Land korrekt.","en":"Around two thirds of Switzerland's foreign population come from an EU/EFTA country, chiefly Italy, Germany, Portugal and France. Italy alone accounts for only part of that, so the broader 'EU country' answer is the correct one.","src":[{"label":"Demografie der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Demografie_der_Schweiz"}]},
  262: {"de":"Die Schweiz hat keinen Zugang zum Meer und ist von Land umgeben, also ein Binnenland (Binnenstaat). Eine Insel, ein Kontinent oder eine Exklave ist sie nicht.","en":"Switzerland has no access to the sea and is surrounded by land, making it a landlocked country. It is not an island, a continent, or an exclave.","src":[{"label":"Binnenstaat – Wikipedia","url":"https://de.wikipedia.org/wiki/Binnenstaat"}]},
  263: {"de":"Das Schweizer Eisenbahnnetz gilt gemessen an der Streckenlänge pro Fläche als das dichteste der Welt. Es ist nicht das längste (absolut betrachtet sind andere Länder grösser) und Aussagen wie schönste oder billigste sind keine messbaren Fakten.","en":"Measured by track length per area, the Swiss railway network is considered the densest in the world. It is not the longest (in absolute terms other countries are larger), and claims like 'most beautiful' or 'cheapest' are not measurable facts.","src":[{"label":"Schienenverkehr in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schienenverkehr_in_der_Schweiz"}]},
  264: {"de":"Die Europäische Union ist mit Abstand der wichtigste Handelspartner der Schweiz; der grösste Teil des Aussenhandels läuft mit EU-Staaten, insbesondere mit dem Nachbarn Deutschland. USA, China und Brasilien folgen erst dahinter.","en":"The European Union is by far Switzerland's most important trading partner; the bulk of foreign trade is with EU states, especially neighbouring Germany. The USA, China and Brazil rank well behind.","src":[{"label":"Wirtschaft der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Wirtschaft_der_Schweiz"}]},
  265: {"de":"Die Schweiz gliedert sich naturräumlich in drei Grossräume: den Jura im Nordwesten, das dicht besiedelte Mittelland und die Alpen im Süden. Die übrigen Antworten nennen einzelne Täler oder Teilregionen, nicht die drei Hauptgebiete.","en":"Geographically Switzerland is divided into three major regions: the Jura in the northwest, the densely populated Central Plateau (Mittelland), and the Alps in the south. The other answers name individual valleys or sub-regions, not the three main areas.","src":[{"label":"Geographie der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Geographie_der_Schweiz"}]},
  266: {"de":"Die Nord-Süd-Ausdehnung der Schweiz beträgt rund 220 km. Die Ost-West-Ausdehnung ist mit etwa 350 km deutlich grösser, weshalb 220 km die richtige Angabe ist.","en":"Switzerland's north-south extent is about 220 km. Its east-west extent is considerably greater at roughly 350 km, which is why 220 km is the correct figure.","src":[{"label":"Geographie der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Geographie_der_Schweiz"}]},
  267: {"de":"Die Ost-West-Ausdehnung der Schweiz beträgt rund 350 km und ist damit die grössere der beiden Achsen (Nord-Süd nur etwa 220 km). Werte wie 700 oder 900 km sind viel zu hoch.","en":"Switzerland's east-west extent is about 350 km, the larger of the two axes (north-south is only around 220 km). Values like 700 or 900 km are far too high.","src":[{"label":"Geographie der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Geographie_der_Schweiz"}]},
  268: {"de":"Das Wallis liegt mitten in den Alpen und gilt mit zahlreichen Viertausendern als typischer Bergkanton. Schaffhausen, Zürich und der Aargau gehören dagegen zum eher flachen Mittelland.","en":"Valais lies in the heart of the Alps and, with its many 4,000-metre peaks, is a classic mountain canton. Schaffhausen, Zürich and Aargau, by contrast, belong to the flatter Central Plateau.","src":[{"label":"Kanton Wallis – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Wallis"}]},
  269: {"de":"Die Dufourspitze im Monte-Rosa-Massiv (Kanton Wallis) ist mit 4634 m der höchste Berg der Schweiz. Dom, Liskamm und Weisshorn sind zwar ebenfalls Viertausender, aber niedriger.","en":"The Dufourspitze in the Monte Rosa massif (Canton Valais), at 4,634 m, is the highest mountain in Switzerland. The Dom, Liskamm and Weisshorn are also 4,000-metre peaks, but lower.","src":[{"label":"Dufourspitze – Wikipedia","url":"https://de.wikipedia.org/wiki/Dufourspitze"}]},
  270: {"de":"Eine zentrale Aufgabe der Raumplanung ist der haushälterische Umgang mit dem Boden und damit der Schutz unverbauter Landschaften vor Zersiedelung. Der Bau von Einkaufszentren oder der Finanzausgleich sind keine Ziele der Raumplanung.","en":"A central task of spatial planning is the careful use of land and thus the protection of undeveloped landscapes from urban sprawl. Building shopping centres or financial equalisation are not aims of spatial planning.","src":[{"label":"Raumplanung in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Raumplanung_in_der_Schweiz"}]},
  271: {"de":"Die Schweizer Gletscher schmelzen, weil durch den Klimawandel die Durchschnittstemperaturen steigen. Touristen, Skirennen oder Sommerregen sind dafür nicht ausschlaggebend.","en":"Switzerland's glaciers are shrinking because average temperatures are rising due to climate change. Tourists, ski races or summer rain are not the decisive factors.","src":[{"label":"Gletscherschmelze – Wikipedia","url":"https://de.wikipedia.org/wiki/Gletscherschmelze"}]},
  272: {"de":"Förster reagieren auf den Temperaturanstieg, indem sie hitze- und trockenheitstolerantere Baumarten anpflanzen, damit der Wald an das veränderte Klima angepasst bleibt. Abholzen, Besprühen oder Arbeitsverweigerung wären keine sinnvollen Massnahmen.","en":"Foresters respond to rising temperatures by planting tree species that tolerate heat and drought better, keeping the forest adapted to the changed climate. Clear-cutting, spraying or refusing to work would not be sensible responses.","src":[{"label":"Forstwirtschaft – Wikipedia","url":"https://de.wikipedia.org/wiki/Forstwirtschaft"}]},
  273: {"de":"Der Föhn ist ein warmer, trockener Fallwind, der in der Schweiz typischerweise aus dem Süden über die Alpen weht. Die Bise dagegen ist ein kalter Nord-/Ostwind.","en":"The Föhn is a warm, dry downslope wind that in Switzerland typically blows from the south across the Alps. The Bise, by contrast, is a cold north/easterly wind.","src":[{"label":"Föhn – Wikipedia","url":"https://de.wikipedia.org/wiki/F%C3%B6hn"}]},
  274: {"de":"Im Westen grenzt die Schweiz an Frankreich. Deutschland liegt im Norden, während Spanien und Portugal gar keine Nachbarländer der Schweiz sind.","en":"To the west, Switzerland borders France. Germany lies to the north, while Spain and Portugal are not neighbours of Switzerland at all.","src":[{"label":"Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz"}]},
  275: {"de":"Im Süden grenzt die Schweiz an Italien. Liechtenstein liegt im Osten, und Spanien wie Kroatien sind keine Nachbarländer.","en":"To the south, Switzerland borders Italy. Liechtenstein lies to the east, and neither Spain nor Croatia is a neighbouring country.","src":[{"label":"Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz"}]},
  276: {"de":"Zürich ist mit rund 430'000 Einwohnern die grösste Stadt der Schweiz, noch vor Genf, Basel und der Bundesstadt Bern.","en":"Zürich, with around 430,000 inhabitants, is the largest city in Switzerland, ahead of Geneva, Basel and the federal city of Bern.","src":[{"label":"Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Z%C3%BCrich"}]},
  277: {"de":"Die meisten Menschen in der Schweiz leben im Mittelland, dem dicht besiedelten Gebiet zwischen Jura und Alpen mit den grossen Städten. Alpen, Jura und Tessin sind deutlich dünner besiedelt.","en":"Most people in Switzerland live on the Central Plateau (Mittelland), the densely populated area between the Jura and the Alps that contains the major cities. The Alps, the Jura and Ticino are much more sparsely populated.","src":[{"label":"Schweizer Mittelland – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_Mittelland"}]},
  278: {"de":"Ende 2020 lebten rund 2,1 Millionen Ausländerinnen und Ausländer in der Schweiz, was etwa einem Viertel der Bevölkerung entspricht. Die anderen Zahlen sind deutlich zu hoch oder zu niedrig.","en":"At the end of 2020 about 2.1 million foreigners lived in Switzerland, roughly a quarter of the population. The other figures are clearly too high or too low.","src":[{"label":"Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz"}]},
  279: {"de":"Der abgebildete Berg mit seiner markanten, pyramidenförmigen Spitze ist das Matterhorn (4478 m) an der Grenze zwischen Wallis und Italien, eines der bekanntesten Wahrzeichen der Schweiz.","en":"The depicted mountain with its distinctive pyramid-shaped peak is the Matterhorn (4,478 m) on the border between Valais and Italy, one of Switzerland's best-known landmarks.","src":[{"label":"Matterhorn – Wikipedia","url":"https://de.wikipedia.org/wiki/Matterhorn"}]},
  280: {"de":"Graubünden ist mit rund 7'105 km² der flächenmässig grösste Kanton der Schweiz. Zürich, Glarus und vor allem die Stadt Basel sind deutlich kleiner.","en":"Graubünden, with around 7,105 km², is the largest canton of Switzerland by area. Zürich, Glarus and especially Basel are considerably smaller.","src":[{"label":"Kanton Graubünden – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Graub%C3%BCnden"}]},
  281: {"de":"Ende 2020 lebten rund 8,6 Millionen Menschen in der Schweiz. Werte wie 5 oder 12 Millionen liegen deutlich daneben.","en":"At the end of 2020 about 8.6 million people lived in Switzerland. Figures such as 5 or 12 million are clearly off the mark.","src":[{"label":"Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz"}]},
  282: {"de":"Der Anteil der ausländischen Wohnbevölkerung lag 2020 bei rund 25 Prozent, also etwa einem Viertel. Werte wie 10 % oder 40 % treffen nicht zu.","en":"Around 2020 the share of foreign residents was roughly 25 percent, about a quarter of the population. Figures like 10% or 40% are incorrect.","src":[{"label":"Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz"}]},
  283: {"de":"Die Schweiz ist reich an Wasser; ihre Flüsse und Seen liefern über Wasserkraftwerke einen Grossteil des Stroms. Nennenswerte Vorkommen an Gold, Erdöl oder Kohle gibt es dagegen nicht.","en":"Switzerland is rich in water; its rivers and lakes supply much of its electricity through hydroelectric power plants. It has no significant deposits of gold, oil or coal.","src":[{"label":"Liste von Wasserkraftwerken in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Liste_von_Wasserkraftwerken_in_der_Schweiz"}]},
  284: {"de":"Der Kanton Freiburg ist offiziell zweisprachig: Es wird sowohl Französisch als auch Deutsch gesprochen. St. Gallen ist deutschsprachig, das Tessin italienisch und Graubünden dreisprachig (Deutsch, Italienisch, Rätoromanisch).","en":"The canton of Fribourg is officially bilingual, with both French and German spoken. St. Gallen is German-speaking, Ticino Italian, and Graubünden trilingual (German, Italian, Romansh).","src":[{"label":"Kanton Freiburg – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Freiburg"}]},
  285: {"de":"Als Welschland oder Romandie bezeichnet man die französischsprachige Schweiz, etwa die Kantone Genf, Waadt, Neuenburg und Jura.","en":"Welschland or Romandie refers to French-speaking Switzerland, including cantons such as Geneva, Vaud, Neuchâtel and Jura.","src":[{"label":"Romandie – Wikipedia","url":"https://de.wikipedia.org/wiki/Romandie"}]},
  286: {"de":"Im Kanton Tessin ist Italienisch die Amtssprache; er ist der einzige rein italienischsprachige Kanton der Schweiz.","en":"In the canton of Ticino the official language is Italian; it is the only entirely Italian-speaking canton of Switzerland.","src":[{"label":"Kanton Tessin – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Tessin"}]},
  287: {"de":"Rätoromanisch wird im Kanton Graubünden gesprochen, dem einzigen dreisprachigen Kanton (Deutsch, Italienisch, Rätoromanisch).","en":"Romansh is spoken in the canton of Graubünden, the only trilingual canton (German, Italian and Romansh).","src":[{"label":"Bündnerromanisch – Wikipedia","url":"https://de.wikipedia.org/wiki/B%C3%BCndnerromanisch"}]},
  288: {"de":"Der Begriff Röstigraben bezeichnet die kulturelle und sprachliche Grenze zwischen der deutschsprachigen und der französischsprachigen Schweiz. Er steht für Mentalitäts- und Abstimmungsunterschiede, nicht für ein geografisches Tal oder eine Staatsgrenze.","en":"The term Röstigraben denotes the cultural and linguistic divide between German-speaking and French-speaking Switzerland. It stands for differences in mentality and voting patterns, not for a geographical valley or a state border.","src":[{"label":"Röstigraben – Wikipedia","url":"https://de.wikipedia.org/wiki/R%C3%B6stigraben"}]},
  289: {"de":"Der Kanton Zürich liegt im Nordosten der Schweiz. Er grenzt im Norden an Deutschland und an mehrere Deutschschweizer Kantone.","en":"The canton of Zürich is located in the northeast of Switzerland. It borders Germany to the north as well as several German-speaking cantons.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  290: {"de":"Der Kanton Zürich liegt grösstenteils im schweizerischen Mittelland, dem flachen bis hügeligen Gebiet zwischen Jura und Alpen. Er gehört weder zum Jura noch zu einer eigenen Seenplatte oder Tössebene.","en":"The canton of Zürich lies mostly in the Swiss Mittelland (Central Plateau), the flat to hilly region between the Jura and the Alps. It belongs neither to the Jura nor to a separate lake district or Töss plain.","src":[{"label":"Schweizer Mittelland – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_Mittelland"}]},
  291: {"de":"Der Kanton Zürich grenzt an sechs andere Kantone: Schaffhausen, Thurgau, St. Gallen, Schwyz, Zug und Aargau (im Norden zudem an Deutschland).","en":"The canton of Zürich borders six other cantons: Schaffhausen, Thurgau, St. Gallen, Schwyz, Zug and Aargau (and to the north also Germany).","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  292: {"de":"Die drei grössten Städte des Kantons Zürich sind Zürich, Winterthur und Uster. Zug und Cham liegen im Kanton Zug, Baden und Wettingen im Kanton Aargau und sind daher keine Zürcher Städte.","en":"The three largest cities in the canton of Zürich are Zürich, Winterthur and Uster. Zug and Cham are in the canton of Zug, while Baden and Wettingen are in Aargau, so they are not Zürich cities.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  293: {"de":"Der Zürichsee wird vom Uetliberg, dem Höhenzug des Albis (Südwestseite) und dem Pfannenstiel (Nordostseite) eingerahmt. Randen, Hörnli, Lägeren und Chli Aubrig gehören nicht zum direkten Seebecken.","en":"Lake Zürich is framed by the Uetliberg, the Albis ridge on the southwest side and the Pfannenstiel on the northeast side. The Randen, Hörnli, Lägeren and Chli Aubrig are not part of the immediate lake basin.","src":[{"label":"Zürichsee – Wikipedia","url":"https://de.wikipedia.org/wiki/Z%C3%BCrichsee"}]},
  294: {"de":"Der Flughafen Zürich liegt grösstenteils auf dem Gemeindegebiet von Kloten und wird umgangssprachlich oft 'Kloten' genannt. Trotz des Namens 'Flughafen Zürich' liegt er nicht in der Stadt Zürich selbst.","en":"Zürich Airport lies mostly within the municipality of Kloten and is colloquially often called 'Kloten'. Despite the name 'Zürich Airport', it is not located in the city of Zürich itself.","src":[{"label":"Flughafen Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Flughafen_Z%C3%BCrich"}]},
  295: {"de":"Der Pfäffikersee liegt im Zürcher Oberland und damit im Kanton Zürich. Hallwilersee, Zugersee und Sempachersee liegen dagegen in den Kantonen Aargau/Luzern, Zug bzw. Luzern.","en":"The Pfäffikersee lies in the Zürcher Oberland and thus within the canton of Zürich. The Hallwilersee, Zugersee and Sempachersee, by contrast, are in the cantons of Aargau/Lucerne, Zug and Lucerne respectively.","src":[{"label":"Pfäffikersee – Wikipedia","url":"https://de.wikipedia.org/wiki/Pf%C3%A4ffikersee"}]},
  296: {"de":"Nach dem Zürichsee ist der Greifensee mit rund 8,5 km² der zweitgrösste See des Kantons Zürich und der grösste See, der vollständig im Kanton liegt. Walensee und Zugersee liegen nicht im Kanton Zürich, und der Sihlsee ist ein Stausee im Kanton Schwyz.","en":"After Lake Zürich, the Greifensee, with about 8.5 km², is the second-largest lake in the canton of Zürich and the largest lake lying entirely within the canton. The Walensee and Zugersee are not in Zürich, and the Sihlsee is a reservoir in the canton of Schwyz.","src":[{"label":"Greifensee – Wikipedia","url":"https://de.wikipedia.org/wiki/Greifensee_(Gew%C3%A4sser)"}]},
  297: {"de":"In der Stadt Zürich mündet die Sihl in die Limmat (beim Platzspitz hinter dem Hauptbahnhof). Aare, Rhone und Ticino fliessen in ganz anderen Regionen der Schweiz.","en":"In the city of Zürich the Sihl flows into the Limmat (at the Platzspitz behind the main station). The Aare, Rhône and Ticino flow in entirely different parts of Switzerland.","src":[{"label":"Sihl – Wikipedia","url":"https://de.wikipedia.org/wiki/Sihl"}]},
  298: {"de":"Die Limmat fliesst aus dem Zürichsee durch die Stadt Zürich und das Limmattal und damit durch den Kanton Zürich. Rhone, Inn und Aare durchfliessen den Kanton Zürich nicht.","en":"The Limmat flows out of Lake Zürich through the city of Zürich and the Limmat valley, and thus through the canton of Zürich. The Rhône, Inn and Aare do not run through the canton.","src":[{"label":"Limmat – Wikipedia","url":"https://de.wikipedia.org/wiki/Limmat"}]},
  299: {"de":"Die Töss fliesst durch das Gemeindegebiet von Winterthur (Quartier Töss) und gibt dem Tösstal ihren Namen; durch das Stadtzentrum selbst fliesst die Eulach. Rhein, Limmat und Sihl berühren Winterthur nicht.","en":"The Töss flows through the municipal area of Winterthur (the Töss district) and gives the Tösstal region its name; the river through the actual city centre is the Eulach. The Rhine, Limmat and Sihl do not pass through Winterthur.","src":[{"label":"Töss (Fluss) – Wikipedia","url":"https://de.wikipedia.org/wiki/T%C3%B6ss_(Fluss)"}]},
  300: {"de":"Das Schloss Kyburg liegt bei Winterthur im Kanton Zürich und ist heute ein Museum. Château de Chillon steht am Genfersee (Waadt), Schloss Hallwyl im Aargau und Schloss Greyerz im Kanton Freiburg.","en":"Kyburg Castle lies near Winterthur in the canton of Zürich and is today a museum. Chillon Castle stands on Lake Geneva (Vaud), Hallwyl Castle is in Aargau, and Gruyères Castle is in the canton of Fribourg.","src":[{"label":"Schloss Kyburg – Wikipedia","url":"https://de.wikipedia.org/wiki/Schloss_Kyburg"}]},
  301: {"de":"Rund 41 Prozent der Fläche des Kantons Zürich werden landwirtschaftlich genutzt; sie bilden damit den grössten Flächenanteil. Werte wie 5 %, 60 % oder 80 % entsprechen nicht der tatsächlichen Bodennutzung.","en":"About 41 percent of the canton of Zürich's area is used for agriculture, making it the largest single land-use share. Figures like 5%, 60% or 80% do not match the actual land use.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  302: {"de":"Der Kanton Zürich ist mit rund 1,5 Millionen Einwohnern (Stand 2020) der bevölkerungsreichste Kanton der Schweiz. 360'000 und 600'000 sind deutlich zu tief, 3,1 Millionen klar zu hoch.","en":"With about 1.5 million inhabitants (as of 2020), the canton of Zürich is the most populous canton in Switzerland. Figures of 360,000 and 600,000 are far too low, and 3.1 million far too high.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  303: {"de":"Die Hauptstadt (der Kantonshauptort) des Kantons Zürich ist die Stadt Zürich, in der auch Kantonsregierung und Kantonsparlament tagen. Uster, Winterthur und Wädenswil sind zwar Zürcher Städte, aber nicht der Hauptort.","en":"The capital (cantonal seat) of the canton of Zürich is the city of Zürich, where the cantonal government and parliament meet. Uster, Winterthur and Wädenswil are Zürich cities but not the cantonal seat.","src":[{"label":"Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Z%C3%BCrich"}]},
  304: {"de":"Der Kanton Thurgau grenzt im Nordosten an den Kanton Zürich. Freiburg, Luzern und Glarus liegen weiter weg und haben keine gemeinsame Grenze mit Zürich (Glarus ist durch Schwyz und St. Gallen getrennt).","en":"The canton of Thurgau borders the canton of Zürich to the northeast. Fribourg, Lucerne and Glarus are farther away and share no border with Zürich (Glarus is separated by Schwyz and St. Gallen).","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  305: {"de":"Jass (das Jassen) ist das traditionelle Schweizer Kartenspiel und in allen Landesteilen verbreitet. Uno, Poker und Bridge sind international, aber nicht typisch schweizerisch.","en":"Jass (jassen) is the traditional Swiss card game, played throughout the country. Uno, poker and bridge are international games, not specifically Swiss.","src":[{"label":"Jass – Wikipedia","url":"https://de.wikipedia.org/wiki/Jass"}]},
  306: {"de":"Der Circus Knie ist der grösste Schweizer Zirkus und wird als «Schweizer Nationalzirkus» bezeichnet. Busch, Krone und Roncalli sind deutsche Zirkusunternehmen.","en":"Circus Knie is the largest Swiss circus and is known as the 'Swiss National Circus'. Busch, Krone and Roncalli are German circus companies.","src":[{"label":"Circus Knie – Wikipedia","url":"https://de.wikipedia.org/wiki/Circus_Knie"}]},
  307: {"de":"Beim «Morgestraich» (Montagmorgen um 4 Uhr) werden in der Basler Innenstadt die Strassenlichter gelöscht, und nur von Laternen beleuchtet beginnen die Pfeifer und Trommler zu spielen. Damit startet offiziell die Basler Fasnacht.","en":"At the 'Morgestraich' (Monday at 4 a.m.) the street lights in Basel's old town are switched off, and lit only by lanterns the pipers and drummers begin to play. This officially opens the Basel Carnival.","src":[{"label":"Basler Fasnacht – Wikipedia","url":"https://de.wikipedia.org/wiki/Basler_Fasnacht"}]},
  308: {"de":"Schwingen ist eine traditionelle Schweizer Sportart, ein Ringkampf im Sägemehl, und gilt als inoffizieller Nationalsport. Basketball, Eishockey und Volleyball sind international und nicht spezifisch schweizerisch.","en":"Schwingen (Swiss wrestling) is a traditional Swiss sport, a form of wrestling in a sawdust ring, regarded as an unofficial national sport. Basketball, ice hockey and volleyball are international, not specifically Swiss.","src":[{"label":"Schwingen – Wikipedia","url":"https://de.wikipedia.org/wiki/Schwingen"}]},
  309: {"de":"Der Schweizer Nationalfeiertag (Bundesfeier) ist der 1. August und erinnert an den Bundesbrief von 1291. Der 14. Juli und 4. Juli sind National­feiertage Frankreichs bzw. der USA, der 3. Oktober jener Deutschlands.","en":"The Swiss national holiday is 1 August, commemorating the Federal Charter of 1291. 14 July and 4 July are the national days of France and the USA, and 3 October is Germany's.","src":[{"label":"Schweizer Bundesfeier – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_Bundesfeier"}]},
  310: {"de":"SBB steht für «Schweizerische Bundesbahnen», die nationale Eisenbahngesellschaft der Schweiz. Die anderen Auflösungen sind frei erfunden.","en":"SBB stands for 'Schweizerische Bundesbahnen' (Swiss Federal Railways), Switzerland's national railway company. The other options are made up.","src":[{"label":"Schweizerische Bundesbahnen – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizerische_Bundesbahnen"}]},
  311: {"de":"SBB, BLS, SOB (Südostbahn) und SZU (Sihltal-Zürich-Uetliberg-Bahn) sind Schweizer Eisenbahngesellschaften, die den Bahnverkehr betreiben. Sie sind weder Gewerkschaften, Kulturvereine noch Seilbahngesellschaften.","en":"SBB, BLS, SOB (Südostbahn) and SZU (Sihltal-Zürich-Uetliberg railway) are Swiss railway companies that operate train services. They are neither trade unions, cultural associations nor cable-car operators.","src":[{"label":"Liste der Schweizer Eisenbahngesellschaften – Wikipedia","url":"https://de.wikipedia.org/wiki/Liste_der_Schweizer_Eisenbahngesellschaften"}]},
  312: {"de":"Heulen im Ernstfall die Alarm-Sirenen (Allgemeiner Alarm), soll man Radio hören und den Anweisungen der Behörden folgen. Das Radio (z. B. SRF) verbreitet im Ereignisfall die offiziellen Verhaltensanweisungen.","en":"If the alarm sirens sound in an emergency (general alarm), you should listen to the radio and follow the authorities' instructions. The radio (e.g. SRF) broadcasts the official behavioural guidance during an event.","src":[{"label":"Sirenenalarm – Wikipedia","url":"https://de.wikipedia.org/wiki/Sirenenalarm"}]},
  313: {"de":"Das Landesmuseum Zürich (Schweizerisches Nationalmuseum) zeigt die Kulturgeschichte der Schweiz von der Frühzeit bis zur Gegenwart. Es ist kein Kunst-, Insekten- oder Automuseum.","en":"The Landesmuseum Zürich (Swiss National Museum) presents the cultural history of Switzerland from early times to the present. It is not an art, insect or car museum.","src":[{"label":"Landesmuseum Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Landesmuseum_Z%C3%BCrich"}]},
  314: {"de":"Die Juraregion ist für ihre Uhrenindustrie bekannt; im Schweizer Jurabogen («Watch Valley») sind viele renommierte Uhrenhersteller angesiedelt. Wurst-, Schuh- oder Seidenmalereiproduktion sind nicht charakteristisch für die Region.","en":"The Jura region is famous for its watchmaking industry; the Swiss Jura arc ('Watch Valley') is home to many renowned watch manufacturers. Sausage, shoe or silk-painting production is not characteristic of the region.","src":[{"label":"Uhrenindustrie – Wikipedia","url":"https://de.wikipedia.org/wiki/Uhrenindustrie"}]},
  315: {"de":"Das Jodeln ist eine bäuerliche, alpenländische Gesangstradition der Schweiz. Didgeridoo (Australien), Kastagnetten (Spanien) und Bembé-Trommeln (afrokubanisch) stammen aus anderen Kulturen.","en":"Yodelling (jodeln) is a rural Alpine singing tradition of Switzerland. The didgeridoo (Australia), castanets (Spain) and bembé drums (Afro-Cuban) come from other cultures.","src":[{"label":"Jodeln – Wikipedia","url":"https://de.wikipedia.org/wiki/Jodeln"}]},
  316: {"de":"Jodeln ist eine besondere Gesangstechnik mit schnellem Wechsel zwischen Brust- und Kopfstimme (Falsett); man braucht dafür also nur die Stimme. Holzschuhe, Pfeifen oder Hände sind keine Voraussetzung.","en":"Yodelling is a special singing technique with rapid switching between chest and head voice (falsetto), so all you need is your voice. Clogs, whistles or hands are not required.","src":[{"label":"Jodeln – Wikipedia","url":"https://de.wikipedia.org/wiki/Jodeln"}]},
  317: {"de":"In der Schweiz herrscht Medien- und Pressefreiheit; die Redaktion einer Zeitung entscheidet unabhängig, welche Artikel veröffentlicht werden. Eine staatliche Medienstelle oder gar eine 'Medienpolizei' gibt es nicht.","en":"Switzerland guarantees freedom of the press, so a newspaper's editorial team decides independently which articles get published. There is no state media office, and certainly no 'media police'.","src":[{"label":"Pressefreiheit – Wikipedia","url":"https://de.wikipedia.org/wiki/Pressefreiheit"}]},
  318: {"de":"Die SonntagsZeitung erscheint nur einmal pro Woche (sonntags) und ist damit eine Wochenzeitung. Tages-Anzeiger, Blick und Neue Zürcher Zeitung sind dagegen Tageszeitungen.","en":"The SonntagsZeitung is published only once a week (on Sundays), making it a weekly paper. The Tages-Anzeiger, Blick and Neue Zürcher Zeitung, by contrast, are dailies.","src":[{"label":"SonntagsZeitung – Wikipedia","url":"https://de.wikipedia.org/wiki/SonntagsZeitung"}]},
  319: {"de":"Die offizielle und historische Bezeichnung der Schweiz lautet 'Schweizerische Eidgenossenschaft'; daher wird sie auch Eidgenossenschaft genannt. Der Name geht auf die mittelalterlichen Bündnisse (Eide) der Orte zurück.","en":"Switzerland's official and historical name is the 'Swiss Confederation', which is why it is also called the Eidgenossenschaft. The term derives from the medieval oath-bound alliances (Eide) between the cantons.","src":[{"label":"Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz"}]},
  320: {"de":"Roger Federer ist einer der erfolgreichsten Tennisspieler aller Zeiten und gewann 20 Grand-Slam-Titel im Einzel. Er ist somit als Tennisspieler bekannt, nicht in einer anderen Sportart.","en":"Roger Federer is one of the most successful tennis players of all time, with 20 Grand Slam singles titles. He is therefore known as a tennis player, not in any other sport.","src":[{"label":"Roger Federer – Wikipedia","url":"https://de.wikipedia.org/wiki/Roger_Federer"}]},
  321: {"de":"Das Rütli ist eine Wiese am Vierwaldstättersee und gilt als Gründungsort der Eidgenossenschaft, wo sich der Sage nach die drei Urkantone Uri, Schwyz und Unterwalden im Rütlischwur verbündeten. Es erinnert also an das Bündnis der Urkantone.","en":"The Rütli is a meadow by Lake Lucerne and is regarded as the founding place of the Confederation, where according to legend the three original cantons Uri, Schwyz and Unterwalden joined together in the Rütli Oath. It thus commemorates the alliance of the original cantons.","src":[{"label":"Rütli – Wikipedia","url":"https://de.wikipedia.org/wiki/R%C3%BCtli"}]},
  322: {"de":"Auf den weissen Schweizer Umlaufmünzen aus Kupfernickel, darunter der 2-Franken-Münze, ist die stehende Helvetia abgebildet – die allegorische weibliche Nationalfigur der Schweiz. Es handelt sich nicht um die Mona Lisa oder eine römische Figur.","en":"The white Swiss circulation coins made of copper-nickel, including the 2-franc coin, depict the standing Helvetia, the allegorical female figure that personifies Switzerland. It is not the Mona Lisa nor a Roman figure.","src":[{"label":"Helvetia – Wikipedia","url":"https://de.wikipedia.org/wiki/Helvetia"}]},
  323: {"de":"Bern ist die Bundesstadt der Schweiz und damit faktisch die Hauptstadt: Hier haben Bundesrat, Bundesversammlung (Parlament) und Bundesverwaltung ihren Sitz. FIFA, UNO und Europarat sitzen nicht in Bern.","en":"Bern is Switzerland's federal city and thus effectively its capital: the Federal Council, the Federal Assembly (parliament) and the federal administration are all based there. FIFA, the UN and the Council of Europe are not located in Bern.","src":[{"label":"Bern – Wikipedia","url":"https://de.wikipedia.org/wiki/Bern"}]},
  324: {"de":"Die Region Basel ist ein bedeutendes Zentrum der Pharmaindustrie; hier haben Grosskonzerne wie Roche und Novartis ihren Sitz. Bekannt ist Basel daher vor allem als Standort grosser Pharmafirmen.","en":"The Basel region is a major centre of the pharmaceutical industry, home to large corporations such as Roche and Novartis. Basel is therefore best known as a location for major pharmaceutical companies.","src":[{"label":"Basel – Wikipedia","url":"https://de.wikipedia.org/wiki/Basel"}]},
  325: {"de":"Der Kanton Zürich ist mit rund 1,6 Millionen Menschen der bevölkerungsreichste Kanton der Schweiz und liegt damit vor Bern und Waadt. St. Gallen hat deutlich weniger Einwohner.","en":"With around 1.6 million people, the canton of Zürich is the most populous canton in Switzerland, ahead of Bern and Vaud. St. Gallen has considerably fewer inhabitants.","src":[{"label":"Kanton Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Kanton_Z%C3%BCrich"}]},
  326: {"de":"Der Schweizer Nationalfeiertag wird am 1. August gefeiert; er erinnert an den Bundesbrief von 1291, der als Gründungsdokument der Eidgenossenschaft gilt.","en":"Switzerland's national day is celebrated on 1 August, commemorating the Federal Charter of 1291, regarded as the founding document of the Confederation.","src":[{"label":"Schweizer Bundesfeiertag – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweizer_Bundesfeiertag"}]},
  327: {"de":"CH steht für 'Confoederatio Helvetica', den lateinischen Namen der Schweizerischen Eidgenossenschaft. Latein wird als neutrale Sprache verwendet, um keine der vier Landessprachen zu bevorzugen.","en":"CH stands for 'Confoederatio Helvetica', the Latin name of the Swiss Confederation. Latin is used as a neutral language so that none of the four national languages is favoured.","src":[{"label":"Confoederatio Helvetica – Wikipedia","url":"https://de.wikipedia.org/wiki/Confoederatio_Helvetica"}]},
  328: {"de":"Skifahren ist im Schweizer Winter ein Volkssport: Die Alpen bieten zahlreiche Skigebiete, und viele Menschen verbringen ihre Freizeit oder Ferien auf der Piste. Schwingen, Berg-Radfahren und Segeln sind dagegen keine typischen Winteraktivitäten.","en":"Skiing is a hugely popular winter activity in Switzerland: the Alps offer numerous ski resorts, and many people spend their free time or holidays on the slopes. Swiss wrestling, mountain biking and sailing are not typical winter pursuits.","src":[{"label":"Skifahren – Wikipedia","url":"https://de.wikipedia.org/wiki/Skifahren"}]},
  329: {"de":"Zur Fasnacht gehören in der Schweiz vor allem kostümierte Maskenumzüge, etwa bei der berühmten Basler Fasnacht. Fahnenschwingen, Jodeln und Bergfeuer gehören zu anderen Traditionen.","en":"In Switzerland, carnival (Fasnacht) is centred on costumed masked parades, as seen at the famous Basel carnival. Flag-throwing, yodelling and mountain bonfires belong to other traditions.","src":[{"label":"Basler Fasnacht – Wikipedia","url":"https://de.wikipedia.org/wiki/Basler_Fasnacht"}]},
  330: {"de":"Die Schweizer Schriftstellerin Johanna Spyri schuf mit «Heidi» eine der weltweit bekanntesten Kinderbuchfiguren. Schellenursli stammt von Selina Chönz, und «Peter und der Wolf» ist ein Werk von Prokofjew.","en":"The Swiss author Johanna Spyri created Heidi, one of the world's best-known children's book characters. Schellenursli was written by Selina Chönz, and 'Peter and the Wolf' is a work by Prokofiev.","src":[{"label":"Heidi – Wikipedia","url":"https://de.wikipedia.org/wiki/Heidi"}]},
  331: {"de":"Max Frisch und Friedrich Dürrenmatt zählen zu den bedeutendsten deutschsprachigen Schriftstellern des 20. Jahrhunderts und stammten beide aus der Schweiz. Bekannt sind etwa Frischs «Homo faber» und Dürrenmatts «Die Physiker».","en":"Max Frisch and Friedrich Dürrenmatt are among the most important German-language writers of the 20th century, both Swiss. Notable works include Frisch's 'Homo Faber' and Dürrenmatt's 'The Physicists'.","src":[{"label":"Max Frisch – Wikipedia","url":"https://de.wikipedia.org/wiki/Max_Frisch"}]},
  332: {"de":"Niki de Saint Phalle, Sophie Taeuber-Arp und Pipilotti Rist sind international bekannte Künstlerinnen mit Schweizer Bezug, tätig in Bildhauerei, Malerei und Videokunst. Politik, Sport oder Ingenieurwesen sind nicht ihre Felder.","en":"Niki de Saint Phalle, Sophie Taeuber-Arp and Pipilotti Rist are internationally renowned artists with Swiss connections, working in sculpture, painting and video art. They are not politicians, athletes or engineers.","src":[{"label":"Pipilotti Rist – Wikipedia","url":"https://de.wikipedia.org/wiki/Pipilotti_Rist"}]},
  333: {"de":"Das Internationale Komitee vom Roten Kreuz (IKRK) hat seinen Hauptsitz in Genf und wurde dort gegründet. Der Internationale Strafgerichtshof sitzt in Den Haag, der Europarat in Strassburg und die OSZE in Wien.","en":"The International Committee of the Red Cross (ICRC) is headquartered in Geneva, where it was founded. The International Criminal Court sits in The Hague, the Council of Europe in Strasbourg and the OSCE in Vienna.","src":[{"label":"Internationales Komitee vom Roten Kreuz – Wikipedia","url":"https://de.wikipedia.org/wiki/Internationales_Komitee_vom_Roten_Kreuz"}]},
  334: {"de":"Die Schweiz trat den Vereinten Nationen (UNO) 2002 nach einer Volksabstimmung bei. Der EU und dem EWR gehört sie nicht an; dem IWF war sie bereits seit 1992 Mitglied.","en":"Switzerland joined the United Nations (UN) in 2002 following a popular vote. It is not a member of the EU or the EEA, and it had already joined the IMF back in 1992.","src":[{"label":"Schweiz in den Vereinten Nationen – Wikipedia","url":"https://de.wikipedia.org/wiki/Schweiz_in_den_Vereinten_Nationen"}]},
  335: {"de":"In der OSZE engagiert sich die Schweiz besonders für Friedenssicherung, Konfliktprävention und Demokratieförderung, namentlich in Osteuropa und Zentralasien. Wirtschaftsentwicklung Indiens, Kraftwerksbau oder Tourismusförderung gehören nicht zu den Kernaufgaben der OSZE.","en":"Within the OSCE, Switzerland is especially active in peacekeeping, conflict prevention and democracy promotion, notably in Eastern Europe and Central Asia. India's economic development, power-plant construction or tourism promotion are not core OSCE tasks.","src":[{"label":"OSZE – Wikipedia","url":"https://de.wikipedia.org/wiki/Organisation_f%C3%BCr_Sicherheit_und_Zusammenarbeit_in_Europa"}]},
  336: {"de":"Die Schweiz ist nicht EU-Mitglied, sondern regelt ihre Beziehungen über die sogenannten Bilateralen Verträge mit der EU. Diese sektoriellen Abkommen wurden mit der EU als Ganzes geschlossen, nicht mit einzelnen Mitgliedstaaten.","en":"Switzerland is not an EU member; instead it governs its relations through the so-called Bilateral Agreements with the EU. These sectoral treaties were concluded with the EU as a whole, not with individual member states.","src":[{"label":"Bilaterale Verträge Schweiz–EU – Wikipedia","url":"https://de.wikipedia.org/wiki/Bilaterale_Vertr%C3%A4ge_zwischen_der_Schweiz_und_der_Europ%C3%A4ischen_Union"}]},
  337: {"de":"Das Weltwirtschaftsforum (WEF) findet jährlich in Davos statt und versammelt Spitzen aus Wirtschaft und Politik. Olympische Winterspiele oder ein jährlicher UNO-Umweltgipfel finden nicht regelmässig in der Schweiz statt.","en":"The World Economic Forum (WEF) takes place annually in Davos, bringing together leaders from business and politics. The Winter Olympics or an annual UN environmental summit are not regularly held in Switzerland.","src":[{"label":"Weltwirtschaftsforum – Wikipedia","url":"https://de.wikipedia.org/wiki/Weltwirtschaftsforum"}]},
  338: {"de":"Das UNO-Menschenrechtsgremium (heute Menschenrechtsrat, früher Menschenrechtskommission) hat seinen Sitz in Genf, dem europäischen Hauptsitz der Vereinten Nationen. Bern, St. Gallen und Neuenburg beherbergen es nicht.","en":"The UN human rights body (today the Human Rights Council, formerly the Commission on Human Rights) is based in Geneva, the UN's European headquarters. It is not located in Bern, St. Gallen or Neuchâtel.","src":[{"label":"UN-Menschenrechtsrat – Wikipedia","url":"https://de.wikipedia.org/wiki/UN-Menschenrechtsrat"}]},
  339: {"de":"Der Weltfussballverband FIFA hat seinen Sitz in Zürich, wo sich auch sein Hauptquartier befindet. Skiverband (FIS), Schwimm- und Golfverband sind anderswo ansässig.","en":"The world football governing body FIFA is headquartered in Zürich, where its main offices are located. The skiing (FIS), swimming and golf federations are based elsewhere.","src":[{"label":"FIFA – Wikipedia","url":"https://de.wikipedia.org/wiki/FIFA"}]},
  340: {"de":"Eine «Chilbi» ist im Schweizerdeutschen ein Jahrmarkt oder Volksfest (von «Kirchweih») mit Fahrgeschäften wie Karussells und Achterbahnen, Buden und Imbissständen. Oper, Fussball oder Schwimmwettkämpfe gehören nicht dazu.","en":"A 'Chilbi' is the Swiss-German term for a funfair or village fair (derived from 'Kirchweih', the church consecration festival), featuring rides such as carousels and roller coasters, stalls and food stands. Opera, football matches or swimming competitions are not part of it.","src":[{"label":"Kirchweih (Chilbi) – Wikipedia","url":"https://de.wikipedia.org/wiki/Kirchweih"}]},
  341: {"de":"Fussball ist die mitgliederstärkste Einzelsportart in Schweizer Vereinen; der Schweizerische Fussballverband zählt rund 1'400 Vereine und gehört zu den mitgliederstärksten Sportverbänden des Landes (nur der polysportive Schweizerische Turnverband hat insgesamt mehr Aktivmitglieder). Schwimmen, Skifahren und Unihockey werden weit weniger oft in Vereinen organisiert ausgeübt.","en":"Football is the single sport with the most club members in Switzerland; the Swiss Football Association comprises around 1,400 clubs and is one of the country's largest sports federations (only the multi-sport Swiss Gymnastics Association has more active members overall). Swimming, skiing and floorball are practised far less often in organised club settings.","src":[{"label":"Sport in der Schweiz – Wikipedia","url":"https://de.wikipedia.org/wiki/Sport_in_der_Schweiz"}]},
  342: {"de":"Nach dem Zürcher Volksglauben sagt die Brenndauer des «Böögg» das Wetter voraus: Je schneller sein mit Knallkörpern gefüllter Kopf explodiert, desto schöner und wärmer soll der kommende Sommer werden. Mit dem Zürichsee, der Geburtenzahl oder der Wirtschaft hat der Brauch nichts zu tun.","en":"According to Zürich folklore, the burning time of the 'Böögg' predicts the weather: the faster its firecracker-filled head explodes, the nicer and warmer the coming summer is supposed to be. The custom has nothing to do with the lake, the birth rate or the economy.","src":[{"label":"Sechseläuten – Wikipedia","url":"https://de.wikipedia.org/wiki/Sechsel%C3%A4uten"}]},
  343: {"de":"Die Street Parade wurde 1992 als «Demonstration für Liebe, Friede, Freiheit, Grosszügigkeit und Toleranz» angemeldet, und dieses Motto ist bis heute ihr Leitgedanke. Sie ist eine Technoparade und kein politisches oder volksmusikalisches Ereignis.","en":"The Street Parade was registered in 1992 as a 'demonstration for love, peace, freedom, generosity and tolerance', and this motto remains its guiding principle to this day. It is a techno parade, not a political or folk-music event.","src":[{"label":"Street Parade – Wikipedia","url":"https://de.wikipedia.org/wiki/Street_Parade"}]},
  344: {"de":"Das Zürcher Theater Spektakel ist ein internationales Festival der darstellenden Künste, das jeden August auf der Landiwiese am Zürichsee Theater, Tanz und Musik aus aller Welt zeigt. Jassturniere, ein Weinfest oder Filmpremieren gehören nicht zum Programm.","en":"The Zürcher Theater Spektakel is an international festival of the performing arts that presents theatre, dance and music from around the world every August on the Landiwiese by Lake Zürich. Card tournaments, a wine festival or film premieres are not part of its programme.","src":[{"label":"Zürcher Theater Spektakel – Wikipedia","url":"https://de.wikipedia.org/wiki/Z%C3%BCrcher_Theater_Spektakel"}]},
  345: {"de":"Weltklasse Zürich ist ein hochkarätiges Leichtathletik-Meeting, das jährlich im Letzigrund-Stadion stattfindet und damit ein klassischer Zürcher Sportevent ist. Der Engadiner Skimarathon, die Swiss Indoors (Basel) und der Schweizer Frauenlauf (Bern) finden ausserhalb Zürichs statt.","en":"Weltklasse Zürich is a top-class track-and-field meeting held annually at the Letzigrund stadium, making it a classic Zürich sporting event. The Engadin Ski Marathon, the Swiss Indoors (Basel) and the Swiss Women's Run (Bern) all take place outside Zürich.","src":[{"label":"Weltklasse Zürich – Wikipedia","url":"https://de.wikipedia.org/wiki/Weltklasse_Z%C3%BCrich"}]},
  346: {"de":"Das Swiss Science Center Technorama steht in Winterthur. Es ist ein Mitmach-Museum, in dem Besucherinnen und Besucher an über 500 Stationen naturwissenschaftliche Phänomene selbst erforschen können.","en":"The Swiss Science Center Technorama is located in Winterthur. It is a hands-on museum where visitors can explore scientific phenomena themselves at over 500 interactive stations.","src":[{"label":"Swiss Science Center Technorama – Wikipedia","url":"https://de.wikipedia.org/wiki/Swiss_Science_Center_Technorama"}]},
  347: {"de":"Das Technorama in Winterthur ist ein Mitmach-Museum, in dem man die Exponate berühren und mit ihnen experimentieren darf. Die anderen genannten Häuser (Sammlung Reinhart, Fotomuseum, Villa Lindengut) sind klassische Ausstellungsmuseen, in denen man nicht selbst experimentiert.","en":"The Technorama in Winterthur is a hands-on museum where you are allowed to touch the exhibits and experiment with them. The other venues listed (Reinhart Collection, Fotomuseum, Villa Lindengut) are classic display museums where you do not experiment yourself.","src":[{"label":"Swiss Science Center Technorama – Wikipedia","url":"https://de.wikipedia.org/wiki/Swiss_Science_Center_Technorama"}]},
  348: {"de":"Die Masoala-Halle befindet sich im Zoo Zürich und bildet auf rund einer Hektare einen tropischen Regenwald aus Madagaskar nach. Sie wurde 2003 eröffnet und beherbergt zahlreiche Tier- und Pflanzenarten der Insel.","en":"The Masoala Hall is located in Zürich Zoo and recreates a tropical rainforest from Madagascar on around one hectare. Opened in 2003, it is home to numerous animal and plant species from the island.","src":[{"label":"Masoala-Halle – Wikipedia","url":"https://de.wikipedia.org/wiki/Masoala-Halle"}]},
  349: {"de":"Das Sechseläuten ist das Frühlingsfest der Zürcher Zünfte: Sie ziehen in historischen Kostümen durch die Stadt und entzünden den Scheiterhaufen mit dem «Böögg». Frauen, Kirchen und Gewerkschaften spielen dabei traditionell keine tragende Rolle.","en":"The Sechseläuten is the spring festival of Zürich's guilds (Zünfte): they parade through the city in historical costumes and light the pyre on which the 'Böögg' burns. Women, churches and trade unions traditionally play no central role in it.","src":[{"label":"Sechseläuten – Wikipedia","url":"https://de.wikipedia.org/wiki/Sechsel%C3%A4uten"}]},
  350: {"de":"Gottfried Keller (1819–1890) war ein bedeutender Zürcher Schriftsteller, bekannt etwa für den Roman «Der grüne Heinrich» und die Novellen «Die Leute von Seldwyla». Er war weder Erfinder noch Pfarrer oder Fabrikant.","en":"Gottfried Keller (1819–1890) was an important writer from Zürich, known for example for the novel 'Der grüne Heinrich' and the novellas 'Die Leute von Seldwyla'. He was neither an inventor nor a pastor nor a factory owner.","src":[{"label":"Gottfried Keller – Wikipedia","url":"https://de.wikipedia.org/wiki/Gottfried_Keller"}]},
};
